import { useState, useEffect, useMemo } from "react";
import { CloudUpload, Clock, AlertTriangle, CheckCircle, Calendar, Download, Shield } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { useSettingsStore } from "@/stores/settingsStore";
import { useDataStore } from "@/stores/dataStore";
import { useExpenseStore } from "@/stores/expenseStore";
import { useSupplierStore } from "@/stores/supplierStore";
import { useReturnStore } from "@/stores/returnStore";
import { useRepStore } from "@/stores/repStore";
import { exportToJSON } from "@/lib/formatters";

const BACKUP_STORAGE_KEY = "ridaa_last_backup";
const BACKUP_SCHEDULE_KEY = "ridaa_backup_schedule";

type Schedule = "daily" | "weekly" | "manual";

function getLastBackup(): string | null {
  return localStorage.getItem(BACKUP_STORAGE_KEY);
}

function setLastBackup() {
  localStorage.setItem(BACKUP_STORAGE_KEY, new Date().toISOString());
}

function getSchedule(): Schedule {
  return (localStorage.getItem(BACKUP_SCHEDULE_KEY) as Schedule) || "weekly";
}

function setScheduleStorage(s: Schedule) {
  localStorage.setItem(BACKUP_SCHEDULE_KEY, s);
}

function daysSinceLastBackup(): number {
  const last = getLastBackup();
  if (!last) return 999;
  return Math.floor((Date.now() - new Date(last).getTime()) / (1000 * 60 * 60 * 24));
}

export function useBackupAlert(): { showAlert: boolean; daysSince: number; lastBackup: string | null } {
  const days = daysSinceLastBackup();
  return {
    showAlert: days >= 7,
    daysSince: days,
    lastBackup: getLastBackup(),
  };
}

export default function BackupScheduler({ compact }: { compact?: boolean } = {}) {
  const { user } = useAuth();
  const { orders, customers, payments } = useDataStore();
  const { expenses } = useExpenseStore();
  const { suppliers, transactions } = useSupplierStore();
  const { returns } = useReturnStore();
  const { reps, commissions } = useRepStore();

  const [schedule, setSchedule] = useState<Schedule>(getSchedule());
  const [lastBackup, setLastBackupState] = useState(getLastBackup());
  const daysSince = daysSinceLastBackup();
  const isOverdue = daysSince >= 7;

  const handleScheduleChange = (s: Schedule) => {
    setSchedule(s);
    setScheduleStorage(s);
    toast.success(`تم تغيير الجدولة إلى: ${s === "daily" ? "يومي" : s === "weekly" ? "أسبوعي" : "يدوي"}`);
  };

  const handleBackupNow = () => {
    const allData = {
      orders, customers, payments, expenses,
      suppliers, transactions, returns, reps, commissions,
      exportDate: new Date().toISOString(),
      version: "3.0",
      schedule,
    };
    exportToJSON(allData, `نسخة-احتياطية-رداء-${new Date().toISOString().split("T")[0]}`);
    setLastBackup();
    setLastBackupState(new Date().toISOString());
    toast.success("تم إنشاء نسخة احتياطية بنجاح");
  };

  const handleGoogleDriveBackup = () => {
    handleBackupNow();
    setTimeout(() => {
      window.open("https://drive.google.com/drive/my-drive", "_blank");
    }, 500);
  };

  const formatLastBackup = () => {
    if (!lastBackup) return "لم يتم أخذ نسخة بعد";
    const d = new Date(lastBackup);
    return d.toLocaleDateString("ar-SA", { year: "numeric", month: "short", day: "numeric", hour: "2-digit", minute: "2-digit" });
  };

  // Check if backup is needed based on schedule
  useEffect(() => {
    if (schedule === "manual") return;
    const needed = schedule === "daily" ? daysSince >= 1 : daysSince >= 7;
    if (needed && orders.length > 0) {
      // Show a notification instead of auto-backing up
      toast.info(
        schedule === "daily"
          ? "حان موعد النسخة الاحتياطية اليومية — اذهب للتصدير"
          : "حان موعد النسخة الاحتياطية الأسبوعية — اذهب للتصدير",
        { duration: 8000 }
      );
    }
  }, []);

  if (compact) {
    return (
      <div className={`rounded-xl p-3 border flex items-center justify-between ${isOverdue ? "bg-red-50 border-red-200" : "bg-emerald-50 border-emerald-200"}`}>
        <div className="flex items-center gap-2">
          {isOverdue ? <AlertTriangle className="size-4 text-red-500" /> : <CheckCircle className="size-4 text-emerald-500" />}
          <div>
            <p className="text-[10px] font-semibold text-gray-700">آخر نسخة: {formatLastBackup()}</p>
            {isOverdue && <p className="text-[9px] text-red-500 font-semibold">⚠️ مر أكثر من {daysSince} يوم بدون نسخة!</p>}
          </div>
        </div>
        <button onClick={handleBackupNow}
          className={`rounded-lg px-3 py-1.5 text-[10px] font-semibold text-white ${isOverdue ? "bg-red-500 hover:bg-red-600" : "bg-emerald-500 hover:bg-emerald-600"} transition-colors`}>
          <Download className="size-3 inline-block me-1" /> نسخ الآن
        </button>
      </div>
    );
  }

  return (
    <div className="rounded-2xl bg-white p-6 shadow-sm border border-gray-100">
      <div className="flex items-center gap-3 mb-5">
        <div className={`rounded-xl p-2.5 ${isOverdue ? "bg-red-50" : "bg-emerald-50"}`}>
          <Shield className={`size-5 ${isOverdue ? "text-red-600" : "text-emerald-600"}`} />
        </div>
        <div>
          <h2 className="text-base font-bold text-navy">جدولة النسخ الاحتياطي</h2>
          <p className="text-xs text-gray-400">حماية بياناتك من الفقدان</p>
        </div>
      </div>

      {/* Last backup status */}
      <div className={`rounded-xl p-4 mb-4 border ${isOverdue ? "bg-red-50 border-red-200" : "bg-emerald-50 border-emerald-200"}`}>
        <div className="flex items-center gap-2 mb-1">
          {isOverdue ? <AlertTriangle className="size-4 text-red-500" /> : <CheckCircle className="size-4 text-emerald-500" />}
          <p className={`text-sm font-bold ${isOverdue ? "text-red-700" : "text-emerald-700"}`}>
            {isOverdue ? `تحذير: لم يتم أخذ نسخة منذ ${daysSince} يوم!` : "النسخ الاحتياطي محدّث"}
          </p>
        </div>
        <div className="flex items-center gap-1.5 text-xs text-gray-500">
          <Clock className="size-3" />
          <span>آخر نسخة: {formatLastBackup()}</span>
        </div>
      </div>

      {/* Schedule selection */}
      <div className="mb-4">
        <p className="text-xs font-semibold text-gray-700 mb-2">جدول النسخ:</p>
        <div className="grid grid-cols-3 gap-2">
          {([
            { key: "daily" as Schedule, label: "يومي", desc: "كل يوم" },
            { key: "weekly" as Schedule, label: "أسبوعي", desc: "كل أسبوع" },
            { key: "manual" as Schedule, label: "يدوي", desc: "عند الحاجة" },
          ]).map((opt) => (
            <button key={opt.key} onClick={() => handleScheduleChange(opt.key)}
              className={`rounded-xl p-3 border-2 text-center transition-all ${
                schedule === opt.key ? "border-navy bg-navy/5" : "border-gray-200 hover:border-gray-300"
              }`}>
              <Calendar className={`size-4 mx-auto mb-1 ${schedule === opt.key ? "text-navy" : "text-gray-400"}`} />
              <p className={`text-xs font-bold ${schedule === opt.key ? "text-navy" : "text-gray-600"}`}>{opt.label}</p>
              <p className="text-[9px] text-gray-400">{opt.desc}</p>
            </button>
          ))}
        </div>
      </div>

      {/* Action buttons */}
      <div className="flex gap-2">
        <button onClick={handleBackupNow}
          className="flex-1 flex items-center justify-center gap-2 rounded-xl bg-navy px-4 py-3 text-xs font-bold text-white shadow-lg shadow-navy/20 hover:bg-navy-light transition-all active:scale-[0.98]">
          <Download className="size-4" /> نسخة احتياطية
        </button>
        <button onClick={handleGoogleDriveBackup}
          className="flex-1 flex items-center justify-center gap-2 rounded-xl bg-blue-600 px-4 py-3 text-xs font-bold text-white shadow-lg shadow-blue-600/20 hover:bg-blue-700 transition-all active:scale-[0.98]">
          <CloudUpload className="size-4" /> رفع لـ Drive
        </button>
      </div>
    </div>
  );
}

import { useState, useMemo, useEffect, useCallback } from "react";
import { MessageCircle, Users, Package, Send, X, CheckCircle, ExternalLink, AlertTriangle, SkipForward, AlertCircle } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { useDataStore } from "@/stores/dataStore";
import { useAuditStore } from "@/stores/auditStore";
import { formatCurrency, validateYemeniPhone } from "@/lib/formatters";
import { WHATSAPP_TEMPLATES } from "@/constants/config";
import { toast } from "sonner";

interface Props {
  open: boolean;
  onClose: () => void;
  mode: "debtors" | "ready";
}

export default function BulkWhatsAppDialog({ open, onClose, mode }: Props) {
  const { user } = useAuth();
  const { orders, getDebtors } = useDataStore();
  const { logAction } = useAuditStore();
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [sending, setSending] = useState(false);
  const [sentCount, setSentCount] = useState(0);
  const [currentRecipient, setCurrentRecipient] = useState<string | null>(null);
  const [waitingForUser, setWaitingForUser] = useState(false);
  const [sendQueue, setSendQueue] = useState<any[]>([]);
  const [queueIndex, setQueueIndex] = useState(0);

  const recipients = useMemo(() => {
    if (mode === "debtors") {
      return getDebtors().map((d) => ({
        id: d.customer.id,
        name: d.customer.name,
        phone: d.customer.phone,
        detail: `مديونية: ${formatCurrency(d.debt)}`,
        message: WHATSAPP_TEMPLATES.paymentReminder(d.customer.name, d.debt),
        amount: d.debt,
        validPhone: validateYemeniPhone(d.customer.phone),
      }));
    }
    return orders.filter((o) => o.status === "ready").map((o) => ({
      id: o.id,
      name: o.customerName,
      phone: o.customerPhone,
      detail: `طلب: ${o.orderNumber}`,
      message: WHATSAPP_TEMPLATES.orderReady(o.customerName, o.orderNumber),
      amount: o.total,
      validPhone: validateYemeniPhone(o.customerPhone),
    }));
  }, [mode, orders, getDebtors]);

  useEffect(() => {
    if (open) {
      // Only select recipients with valid phone numbers
      setSelectedIds(new Set(recipients.filter(r => r.validPhone).map((r) => r.id)));
      setSentCount(0);
      setSending(false);
      setWaitingForUser(false);
      setSendQueue([]);
      setQueueIndex(0);
      setCurrentRecipient(null);
    }
  }, [open, recipients]);

  const toggleId = (id: string) => {
    setSelectedIds((prev) => {
      const next = new Set(prev);
      if (next.has(id)) next.delete(id); else next.add(id);
      return next;
    });
  };

  const toggleAll = () => {
    const validRecipients = recipients.filter(r => r.validPhone);
    if (selectedIds.size === validRecipients.length) setSelectedIds(new Set());
    else setSelectedIds(new Set(validRecipients.map((r) => r.id)));
  };

  const openWhatsApp = (phone: string, message: string) => {
    const cleanPhone = phone.replace(/\D/g, "");
    const fullPhone = cleanPhone.startsWith("967") ? cleanPhone : `967${cleanPhone}`;
    const encoded = encodeURIComponent(message);
    const link = document.createElement("a");
    link.href = `https://wa.me/${fullPhone}?text=${encoded}`;
    link.target = "_blank";
    link.rel = "noopener noreferrer";
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleSendAll = () => {
    const selected = recipients.filter((r) => selectedIds.has(r.id));
    if (selected.length === 0) { toast.error("اختر على الأقل مستلماً واحداً"); return; }

    // Filter out invalid phones
    const validSelected = selected.filter(r => r.validPhone);
    if (validSelected.length === 0) { toast.error("لا يوجد مستلم برقم هاتف صالح"); return; }

    const invalidCount = selected.length - validSelected.length;
    if (invalidCount > 0) {
      toast.warning(`تم تخطي ${invalidCount} مستلم بسبب أرقام هاتف غير صحيحة`);
    }

    setSending(true);
    setSendQueue(validSelected);
    setQueueIndex(0);
    setSentCount(0);

    // Open first one immediately
    const first = validSelected[0];
    setCurrentRecipient(first.name);
    openWhatsApp(first.phone, first.message);
    setSentCount(1);
    setQueueIndex(1);

    if (validSelected.length === 1) {
      finishSending(1);
    } else {
      setWaitingForUser(true);
    }
  };

  const handleSendNext = () => {
    if (queueIndex >= sendQueue.length) {
      finishSending(sentCount);
      return;
    }
    const next = sendQueue[queueIndex];
    setCurrentRecipient(next.name);
    openWhatsApp(next.phone, next.message);
    setSentCount((c) => c + 1);
    setQueueIndex((i) => i + 1);

    if (queueIndex + 1 >= sendQueue.length) {
      // Last one
      setTimeout(() => finishSending(sentCount + 1), 500);
    }
  };

  const finishSending = (count: number) => {
    if (user?.id) {
      logAction(user.id, "bulk_whatsapp", "system", undefined,
        `إرسال واتساب جماعي (${mode === "debtors" ? "مدينين" : "طلبات جاهزة"}) — ${count} مستلم`);
    }
    setSending(false);
    setWaitingForUser(false);
    toast.success(`تم إرسال ${count} رسالة واتساب بنجاح ✅`);
    onClose();
  };

  const handleSkipRest = () => {
    finishSending(sentCount);
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="w-full max-w-lg rounded-2xl bg-white shadow-xl max-h-[85vh] flex flex-col animate-fade-in">
        {/* Header */}
        <div className="flex items-center justify-between border-b p-5">
          <div className="flex items-center gap-3">
            <div className={`rounded-xl p-2.5 ${mode === "debtors" ? "bg-red-50" : "bg-emerald-50"}`}>
              {mode === "debtors" ? <AlertTriangle className="size-5 text-red-600" /> : <Package className="size-5 text-emerald-600" />}
            </div>
            <div>
              <h2 className="text-base font-bold text-navy">
                {mode === "debtors" ? "مطالبة المدينين جماعياً" : "إبلاغ الطلبات الجاهزة"}
              </h2>
              <p className="text-xs text-gray-400">{recipients.length} مستلم متاح</p>
            </div>
          </div>
          <button onClick={onClose} className="rounded-lg p-2 hover:bg-gray-100"><X className="size-5 text-gray-400" /></button>
        </div>

        {/* Select all */}
        <div className="flex items-center justify-between border-b px-5 py-3 bg-cream/40">
          <label className="flex items-center gap-2 cursor-pointer">
            <input type="checkbox" checked={selectedIds.size === recipients.filter(r => r.validPhone).length && recipients.length > 0}
              onChange={toggleAll} className="size-4 rounded border-gray-300 accent-navy" />
            <span className="text-sm font-semibold text-navy">تحديد الكل ({selectedIds.size}/{recipients.filter(r => r.validPhone).length})</span>
          </label>
          {sending && <span className="text-xs text-emerald-600 font-semibold animate-pulse">تم إرسال {sentCount}/{sendQueue.length}</span>}
        </div>

        {/* Invalid phones warning */}
        {recipients.filter(r => !r.validPhone).length > 0 && (
          <div className="mx-5 mt-2 rounded-lg bg-amber-50 border border-amber-200 px-3 py-2 flex items-center gap-2">
            <AlertCircle className="size-4 text-amber-600 shrink-0" />
            <span className="text-xs text-amber-700 font-semibold">
              {recipients.filter(r => !r.validPhone).length} أرقام غير صالحة (ناقصة أو خاطئة) — لن يتم إرسالها
            </span>
          </div>
        )}

        {/* Recipients list */}
        <div className="flex-1 overflow-y-auto p-3 space-y-1.5">
          {recipients.length === 0 ? (
            <div className="flex flex-col items-center gap-3 py-12">
              <CheckCircle className="size-10 text-green-400" />
              <p className="text-sm text-gray-500">
                {mode === "debtors" ? "لا يوجد مدينون حالياً 🎉" : "لا توجد طلبات جاهزة للتسليم"}
              </p>
            </div>
          ) : (
            recipients.map((r) => (
              <label key={r.id}
                className={`flex items-center gap-3 rounded-xl p-3 cursor-pointer transition-colors ${!r.validPhone ? "bg-red-50 border border-red-200 opacity-70" : selectedIds.has(r.id) ? "bg-emerald-50 border border-emerald-200" : "bg-gray-50 border border-transparent hover:bg-gray-100"}`}>
                <input type="checkbox" checked={selectedIds.has(r.id)} onChange={() => toggleId(r.id)}
                  disabled={!r.validPhone}
                  className="size-4 rounded border-gray-300 accent-emerald-600 shrink-0 disabled:opacity-40" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-semibold text-navy truncate">{r.name}</p>
                  <div className="flex items-center gap-1">
                    <p className="text-[10px] text-gray-400" dir="ltr">+{r.phone.replace(/\D/g, "").replace(/^(?!967)/, "967")}</p>
                    {!r.validPhone && (
                      <span className="text-[9px] font-bold text-red-500 bg-red-100 px-1 rounded">رقم ناقص!</span>
                    )}
                  </div>
                </div>
                <span className={`shrink-0 text-xs font-bold tabular-nums ${!r.validPhone ? "text-red-400" : mode === "debtors" ? "text-red-600" : "text-emerald-600"}`}>
                  {r.detail}
                </span>
              </label>
            ))
          )}
        </div>

        {/* Footer */}
        <div className="border-t p-5 space-y-3">
          {waitingForUser && (
            <div className="rounded-xl bg-blue-50 border border-blue-200 p-3 text-center">
              <p className="text-xs font-semibold text-blue-700 mb-1">
                ✅ تم إرسال لـ "{currentRecipient}" — اضغط "التالي" لإرسال الرسالة القادمة
              </p>
              <p className="text-[10px] text-blue-500">تم {sentCount} من {sendQueue.length}</p>
            </div>
          )}
          <div className="flex items-center gap-3">
            <button onClick={onClose}
              className="flex-1 rounded-xl border border-gray-200 py-3 text-sm font-semibold text-gray-600 hover:bg-gray-50 transition-colors">
              {sending ? "إغلاق" : "إلغاء"}
            </button>
            {waitingForUser ? (
              <>
                <button onClick={handleSkipRest}
                  className="flex items-center justify-center gap-2 rounded-xl border border-amber-200 bg-amber-50 px-4 py-3 text-sm font-semibold text-amber-700 hover:bg-amber-100 transition-colors">
                  <SkipForward className="size-4" /> إنهاء
                </button>
                <button onClick={handleSendNext}
                  className="flex-1 flex items-center justify-center gap-2 rounded-xl bg-emerald-500 py-3 text-sm font-bold text-white hover:bg-emerald-600 transition-colors">
                  <Send className="size-4" /> التالي ({queueIndex + 1}/{sendQueue.length})
                </button>
              </>
            ) : (
              <button onClick={handleSendAll} disabled={sending || selectedIds.size === 0}
                className="flex-1 flex items-center justify-center gap-2 rounded-xl bg-emerald-500 py-3 text-sm font-bold text-white hover:bg-emerald-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors">
                <MessageCircle className="size-4" />
                إرسال لـ {selectedIds.size} شخص
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useMemo, useRef, useState } from "react";
import { Search, X, Users, ShoppingBag, Package, Truck, UserCheck, FileText, Command } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { useDataStore } from "@/stores/dataStore";
import { useAuth } from "@/hooks/useAuth";
import { useSupplierStore } from "@/stores/supplierStore";
import { useRepStore } from "@/stores/repStore";
import { supabase } from "@/lib/supabase";

interface SearchResult {
  id: string;
  type: "customer" | "order" | "product" | "supplier" | "rep" | "invoice";
  title: string;
  subtitle: string;
  icon: typeof Users;
  color: string;
  path: string;
}

interface Props {
  onClose?: () => void;
}

export default function GlobalSearch({ onClose }: Props) {
  const { user } = useAuth();
  const navigate = useNavigate();
  const { customers, orders, initializeData } = useDataStore();
  const { suppliers, initializeData: initSup } = useSupplierStore();
  const { reps, initializeData: initReps } = useRepStore();
  const [query, setQuery] = useState("");
  const [products, setProducts] = useState<Array<{ id: string; code: string; name: string; category: string; sell_price: number }>>([]);
  const [activeIndex, setActiveIndex] = useState(0);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (user?.id) {
      initializeData(user.id);
      initSup(user.id);
      initReps(user.id);
      supabase.from("products").select("id, code, name, category, sell_price").eq("is_active", true).then(({ data }) => {
        if (data) setProducts(data);
      });
    }
    inputRef.current?.focus();
  }, [user?.id]);

  const results = useMemo<SearchResult[]>(() => {
    const q = query.trim().toLowerCase();
    if (!q) return [];
    const all: SearchResult[] = [];

    // Customers
    customers.filter((c) => c.name.toLowerCase().includes(q) || c.phone.includes(q) || c.city?.toLowerCase().includes(q))
      .slice(0, 5).forEach((c) => {
        all.push({
          id: c.id, type: "customer", title: c.name, subtitle: `${c.phone}${c.city ? ` · ${c.city}` : ""}`,
          icon: Users, color: "text-purple-600 bg-purple-50", path: `/customers/${c.id}`,
        });
      });

    // Orders
    orders.filter((o) => o.orderNumber.toLowerCase().includes(q) || o.customerName.toLowerCase().includes(q))
      .slice(0, 5).forEach((o) => {
        all.push({
          id: o.id, type: "order", title: `طلب ${o.orderNumber}`, subtitle: `${o.customerName} · ${o.total.toLocaleString()} ر.ي`,
          icon: ShoppingBag, color: "text-blue-600 bg-blue-50", path: `/invoice/${o.id}`,
        });
      });

    // Products
    products.filter((p) => p.name.toLowerCase().includes(q) || p.code.toLowerCase().includes(q))
      .slice(0, 5).forEach((p) => {
        all.push({
          id: p.id, type: "product", title: p.name, subtitle: `${p.code} · ${p.category}`,
          icon: Package, color: "text-emerald-600 bg-emerald-50", path: "/products",
        });
      });

    // Suppliers
    suppliers.filter((s) => s.name.toLowerCase().includes(q) || s.company?.toLowerCase().includes(q) || s.phone.includes(q))
      .slice(0, 3).forEach((s) => {
        all.push({
          id: s.id, type: "supplier", title: s.name, subtitle: `${s.company || s.phone}`,
          icon: Truck, color: "text-amber-600 bg-amber-50", path: "/suppliers",
        });
      });

    // Reps
    reps.filter((r) => r.name.toLowerCase().includes(q) || r.email?.toLowerCase().includes(q) || r.phone?.includes(q))
      .slice(0, 3).forEach((r) => {
        all.push({
          id: r.id, type: "rep", title: r.name, subtitle: `${r.email || r.phone || "-"} · ${r.commissionRate}%`,
          icon: UserCheck, color: "text-cyan-600 bg-cyan-50", path: "/reps",
        });
      });

    return all.slice(0, 20);
  }, [query, customers, orders, products, suppliers, reps]);

  const handleSelect = (r: SearchResult) => {
    navigate(r.path);
    onClose?.();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setActiveIndex((prev) => Math.min(prev + 1, results.length - 1));
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setActiveIndex((prev) => Math.max(prev - 1, 0));
    } else if (e.key === "Enter" && results[activeIndex]) {
      handleSelect(results[activeIndex]);
    } else if (e.key === "Escape") {
      onClose?.();
    }
  };

  return (
    <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-start justify-center p-4 sm:pt-24 animate-fade-in" onClick={onClose}>
      <div className="w-full max-w-2xl bg-white rounded-2xl shadow-2xl overflow-hidden" onClick={(e) => e.stopPropagation()}>
        <div className="flex items-center gap-3 border-b px-4 py-3">
          <Search className="size-5 text-gray-400" />
          <input ref={inputRef} value={query} onChange={(e) => { setQuery(e.target.value); setActiveIndex(0); }}
            onKeyDown={handleKeyDown}
            placeholder="ابحث في: العملاء، الطلبات، المنتجات، الموردين، المندوبين..."
            className="flex-1 border-0 focus:outline-none text-sm placeholder:text-gray-400" />
          <div className="flex items-center gap-2">
            <span className="hidden sm:flex items-center gap-1 text-[10px] text-gray-400 border border-gray-200 rounded-md px-1.5 py-0.5">
              <Command className="size-3" /> K
            </span>
            <button onClick={onClose} className="rounded-lg p-1 text-gray-400 hover:bg-gray-100">
              <X className="size-4" />
            </button>
          </div>
        </div>

        <div className="max-h-[400px] overflow-y-auto">
          {!query ? (
            <div className="p-6 text-center text-gray-400">
              <Search className="mx-auto size-8 text-gray-300 mb-2" />
              <p className="text-sm">ابدأ بالكتابة للبحث في جميع البيانات</p>
              <div className="mt-4 flex flex-wrap gap-1.5 justify-center">
                <span className="rounded-md bg-gray-100 px-2 py-1 text-[10px]">↑ ↓ للتنقل</span>
                <span className="rounded-md bg-gray-100 px-2 py-1 text-[10px]">Enter للاختيار</span>
                <span className="rounded-md bg-gray-100 px-2 py-1 text-[10px]">Esc للإغلاق</span>
              </div>
            </div>
          ) : results.length === 0 ? (
            <div className="p-6 text-center text-gray-400">
              <FileText className="mx-auto size-8 text-gray-300 mb-2" />
              <p className="text-sm">لا توجد نتائج لـ "{query}"</p>
            </div>
          ) : (
            <div className="py-2">
              {results.map((r, i) => {
                const Icon = r.icon;
                return (
                  <button key={`${r.type}-${r.id}`} onClick={() => handleSelect(r)}
                    onMouseEnter={() => setActiveIndex(i)}
                    className={`w-full flex items-center gap-3 px-4 py-2.5 text-right transition-colors ${
                      activeIndex === i ? "bg-cream/60" : "hover:bg-gray-50"
                    }`}>
                    <div className={`rounded-lg p-2 ${r.color}`}>
                      <Icon className="size-4" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-sm font-bold text-navy truncate">{r.title}</p>
                      <p className="text-[11px] text-gray-500 truncate">{r.subtitle}</p>
                    </div>
                    <span className="text-[9px] font-bold text-gray-400 bg-gray-100 rounded px-1.5 py-0.5">
                      {r.type === "customer" ? "عميل" : r.type === "order" ? "طلب" : r.type === "product" ? "منتج" : r.type === "supplier" ? "مورد" : r.type === "rep" ? "مندوب" : "فاتورة"}
                    </span>
                  </button>
                );
              })}
            </div>
          )}
        </div>

        {results.length > 0 && (
          <div className="border-t px-4 py-2 bg-gray-50 text-[10px] text-gray-500 flex items-center justify-between">
            <span>{results.length} نتيجة</span>
            <span>اضغط Enter للفتح</span>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { X, Plus, Trash2, Search, Calculator, AlertCircle, CheckCircle2, Phone, Edit3, Save } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { useDataStore } from "@/stores/dataStore";
import { useRepStore } from "@/stores/repStore";
import { findProductByCode, searchProducts, PRODUCT_CATALOG } from "@/constants/productCatalog";
import { generateId } from "@/lib/utils";
import { formatCurrency, validateYemeniPhone, formatPhone } from "@/lib/formatters";
import type { OrderItem, OrderStatus, PaymentStatus } from "@/types";

interface Props { open: boolean; onClose: () => void; }

export default function OrderFormDialog({ open, onClose }: Props) {
  const { user } = useAuth();
  const { customers, addOrder, updateCustomer } = useDataStore();
  const { reps } = useRepStore();
  const [customerId, setCustomerId] = useState("");
  const [repId, setRepId] = useState("");
  const [items, setItems] = useState<(OrderItem & { codeInput?: string })[]>([
    { id: generateId(), productCode: "", productName: "", quantity: 1, unitPrice: 0, buyPrice: 0, total: 0, codeInput: "" },
  ]);
  const [discount, setDiscount] = useState(0);
  const [paid, setPaid] = useState(0);
  const [notes, setNotes] = useState("");
  const [dueDate, setDueDate] = useState("");
  const [activeSearch, setActiveSearch] = useState<string | null>(null);
  const [searchResults, setSearchResults] = useState<typeof PRODUCT_CATALOG>([]);

  // Phone validation widget state
  const [showPhoneEdit, setShowPhoneEdit] = useState(false);
  const [editingPhone, setEditingPhone] = useState("");
  const [savingPhone, setSavingPhone] = useState(false);

  const selectedCustomer = customers.find((c) => c.id === customerId);
  const customerPhoneValid = selectedCustomer ? validateYemeniPhone(selectedCustomer.phone) : true;

  useEffect(() => {
    if (selectedCustomer) {
      setEditingPhone(selectedCustomer.phone);
      setShowPhoneEdit(false);
    }
  }, [customerId]);

  if (!open) return null;

  const subtotal = items.reduce((s, i) => s + i.total, 0);
  const total = subtotal - discount;
  const remaining = total - paid;

  const addItem = () => {
    setItems([...items, { id: generateId(), productCode: "", productName: "", quantity: 1, unitPrice: 0, buyPrice: 0, total: 0, codeInput: "" }]);
  };

  const removeItem = (id: string) => { if (items.length > 1) setItems(items.filter((i) => i.id !== id)); };

  const handleCodeInput = (itemId: string, code: string) => {
    setItems(items.map((item) => {
      if (item.id !== itemId) return item;
      const updated = { ...item, codeInput: code };
      const product = findProductByCode(code);
      if (product) {
        updated.productCode = product.code;
        updated.productName = product.name;
        updated.unitPrice = product.sellPrice;
        updated.buyPrice = product.totalCost;
        updated.total = product.sellPrice * updated.quantity;
        setActiveSearch(null);
        setSearchResults([]);
      } else if (code.length >= 2) {
        setActiveSearch(itemId);
        setSearchResults(searchProducts(code).slice(0, 8));
      }
      return updated;
    }));
  };

  const selectProduct = (itemId: string, product: typeof PRODUCT_CATALOG[0]) => {
    setItems(items.map((item) => {
      if (item.id !== itemId) return item;
      return { ...item, codeInput: product.code, productCode: product.code, productName: product.name,
        unitPrice: product.sellPrice, buyPrice: product.totalCost, total: product.sellPrice * item.quantity };
    }));
    setActiveSearch(null); setSearchResults([]);
  };

  const updateItemField = (id: string, field: string, value: number) => {
    setItems(items.map((item) => {
      if (item.id !== id) return item;
      const updated = { ...item, [field]: value };
      if (field === "quantity" || field === "unitPrice") updated.total = updated.quantity * updated.unitPrice;
      return updated;
    }));
  };

  const handleSavePhone = async () => {
    if (!selectedCustomer) return;
    if (!editingPhone.trim()) { toast.error("الرقم لا يمكن أن يكون فارغاً"); return; }
    if (!validateYemeniPhone(editingPhone)) { toast.error("الرقم غير صحيح"); return; }
    setSavingPhone(true);
    const cleanPhone = editingPhone.replace(/\D/g, "");
    await updateCustomer(selectedCustomer.id, { phone: cleanPhone });
    toast.success("تم تحديث رقم العميل");
    setSavingPhone(false);
    setShowPhoneEdit(false);
  };

  const handleSubmit = async () => {
    const customer = customers.find((c) => c.id === customerId);
    if (!customer) { toast.error("يرجى اختيار العميل"); return; }
    if (!validateYemeniPhone(customer.phone)) {
      toast.error("رقم هاتف العميل غير صحيح — قم بتحديثه أولاً");
      return;
    }
    if (items.some((i) => !i.productName)) { toast.error("يرجى اختيار المنتج لجميع العناصر"); return; }
    if (!user?.id) return;

    let paymentStatus: PaymentStatus = "unpaid";
    if (paid >= total) paymentStatus = "paid";
    else if (paid > 0) paymentStatus = "partial";

    const rep = reps.find((r) => r.id === repId);

    await addOrder({
      customerId: customer.id, customerName: customer.name, customerPhone: customer.phone,
      repId: rep?.id, repName: rep?.name,
      items: items.map(({ codeInput, ...rest }) => rest),
      subtotal, discount, total, paid, remaining: Math.max(0, remaining),
      status: "pending" as OrderStatus, paymentStatus, notes,
      createdAt: new Date().toISOString().split("T")[0],
      dueDate: dueDate || new Date(Date.now() + 10 * 86400000).toISOString().split("T")[0],
    }, user.id);

    if (rep) {
      const commissionAmount = total * (rep.commissionRate / 100);
      useRepStore.getState().addCommission({
        repId: rep.id, repName: rep.name, orderId: "", orderNumber: "",
        orderTotal: total, commissionAmount, shippingDeduction: 0, netCommission: commissionAmount,
        isPaid: false, date: new Date().toISOString().split("T")[0], notes: "",
      });
    }

    toast.success("تم إنشاء الطلب بنجاح");
    onClose();
    setCustomerId(""); setRepId(""); setDiscount(0); setPaid(0); setNotes(""); setDueDate("");
    setItems([{ id: generateId(), productCode: "", productName: "", quantity: 1, unitPrice: 0, buyPrice: 0, total: 0, codeInput: "" }]);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-2 sm:p-4">
      <div className="w-full max-w-3xl animate-scale-in rounded-2xl bg-white shadow-2xl max-h-[95vh] overflow-y-auto scrollbar-thin">
        <div className="sticky top-0 z-10 flex items-center justify-between border-b bg-white px-4 py-3 rounded-t-2xl sm:px-6 sm:py-4">
          <h2 className="text-base font-bold text-navy sm:text-lg">طلب جديد</h2>
          <button onClick={onClose} className="rounded-lg p-2 hover:bg-gray-100" aria-label="إغلاق"><X className="size-5" /></button>
        </div>
        <div className="space-y-4 p-4 sm:space-y-5 sm:p-6">
          <div className="grid grid-cols-1 gap-3 sm:grid-cols-3 sm:gap-4">
            <div>
              <label className="mb-1.5 block text-sm font-semibold text-gray-700">العميل</label>
              <select value={customerId} onChange={(e) => setCustomerId(e.target.value)}
                className="w-full rounded-xl border border-gray-200 bg-white px-4 py-2.5 text-sm focus:border-gold focus:outline-none">
                <option value="">اختر العميل...</option>
                {customers.map((c) => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
            </div>
            <div>
              <label className="mb-1.5 block text-sm font-semibold text-gray-700">المندوب/المسوقة</label>
              <select value={repId} onChange={(e) => setRepId(e.target.value)}
                className="w-full rounded-xl border border-gray-200 bg-white px-4 py-2.5 text-sm focus:border-gold focus:outline-none">
                <option value="">بدون مندوب</option>
                {reps.filter((r) => r.isActive).map((r) => <option key={r.id} value={r.id}>{r.name} ({r.commissionRate}%)</option>)}
              </select>
            </div>
            <div>
              <label className="mb-1.5 block text-sm font-semibold text-gray-700">تاريخ التسليم</label>
              <input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)}
                className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none" />
            </div>
          </div>

          {/* Phone Validation Widget */}
          {selectedCustomer && (
            <div className={`rounded-xl border-2 p-3 ${
              customerPhoneValid ? "bg-emerald-50 border-emerald-200" : "bg-red-50 border-red-300"
            }`}>
              {!showPhoneEdit ? (
                <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`rounded-lg p-2 ${customerPhoneValid ? "bg-emerald-100" : "bg-red-100"}`}>
                      {customerPhoneValid ?
                        <CheckCircle2 className="size-4 text-emerald-600" /> :
                        <AlertCircle className="size-4 text-red-600" />}
                    </div>
                    <div>
                      <p className={`text-xs font-bold ${customerPhoneValid ? "text-emerald-800" : "text-red-800"}`}>
                        {customerPhoneValid ? "رقم هاتف العميل صحيح" : "⚠️ تنبيه: رقم العميل ناقص أو غير صحيح"}
                      </p>
                      <p className="text-xs text-gray-600 flex items-center gap-1.5 mt-0.5">
                        <Phone className="size-3" />
                        <span dir="ltr">{selectedCustomer.phone || "(فارغ)"}</span>
                        {!customerPhoneValid && (
                          <span className="text-red-500 text-[10px]">— لن يصل واتساب أو SMS لهذا الرقم</span>
                        )}
                      </p>
                    </div>
                  </div>
                  <button type="button" onClick={() => setShowPhoneEdit(true)}
                    className={`flex items-center gap-1.5 rounded-lg px-3 py-1.5 text-xs font-semibold transition-colors ${
                      customerPhoneValid ?
                        "bg-emerald-100 text-emerald-700 hover:bg-emerald-200" :
                        "bg-red-600 text-white hover:bg-red-700"
                    }`}>
                    <Edit3 className="size-3" /> {customerPhoneValid ? "تعديل" : "تحديث الرقم الآن"}
                  </button>
                </div>
              ) : (
                <div className="space-y-2">
                  <p className="text-xs font-bold text-navy">تحديث رقم {selectedCustomer.name}</p>
                  <div className="flex gap-2">
                    <input value={editingPhone} onChange={(e) => setEditingPhone(e.target.value)} dir="ltr"
                      className="flex-1 rounded-lg border-2 border-gold/30 bg-white px-4 py-2 text-sm focus:border-gold focus:outline-none"
                      placeholder="967 7xx xxx xxx" autoFocus />
                    <button onClick={handleSavePhone} disabled={savingPhone}
                      className="flex items-center gap-1 rounded-lg bg-emerald-600 px-3 py-2 text-xs font-semibold text-white hover:bg-emerald-700 disabled:opacity-50">
                      <Save className="size-3.5" /> حفظ
                    </button>
                    <button onClick={() => { setShowPhoneEdit(false); setEditingPhone(selectedCustomer.phone); }}
                      className="rounded-lg border border-gray-300 bg-white px-3 py-2 text-xs font-semibold text-gray-600 hover:bg-gray-50">
                      إلغاء
                    </button>
                  </div>
                  {editingPhone && !validateYemeniPhone(editingPhone) && (
                    <p className="text-[10px] text-red-500">⚠️ الرقم غير صحيح — يجب أن يكون 9+ أرقام يبدأ بـ 7 أو 967</p>
                  )}
                </div>
              )}
            </div>
          )}

          <div>
            <div className="mb-2 flex items-center justify-between">
              <label className="text-sm font-semibold text-gray-700">المنتجات</label>
              <button type="button" onClick={addItem} className="flex items-center gap-1 rounded-lg bg-navy/10 px-3 py-1.5 text-xs font-semibold text-navy hover:bg-navy/20">
                <Plus className="size-3.5" /> إضافة
              </button>
            </div>
            <div className="mb-2 flex items-center gap-2 rounded-lg bg-gold/10 px-3 py-2 text-[11px] text-gold-dark sm:text-xs">
              <Search className="size-3.5 shrink-0" /> أدخل رمز المنتج (مثل RM-812) وسيظهر السعر تلقائياً
            </div>
            <div className="space-y-3">
              {items.map((item) => (
                <div key={item.id} className="rounded-xl border border-gray-100 bg-cream/30 p-3">
                  <div className="grid grid-cols-12 gap-2 items-end">
                    <div className="col-span-5 sm:col-span-4 relative">
                      <label className="mb-1 block text-[10px] font-medium text-gray-400">رمز المنتج</label>
                      <input value={item.codeInput || ""} onChange={(e) => handleCodeInput(item.id, e.target.value)}
                        onFocus={() => { if ((item.codeInput?.length || 0) >= 2) { setActiveSearch(item.id); setSearchResults(searchProducts(item.codeInput || "").slice(0, 8)); } }}
                        onBlur={() => setTimeout(() => setActiveSearch(null), 200)}
                        className="w-full rounded-lg border border-gray-200 bg-white px-3 py-2 text-sm focus:border-gold focus:outline-none" placeholder="RM-812" dir="ltr" />
                      {activeSearch === item.id && searchResults.length > 0 && (
                        <div className="absolute top-full left-0 right-0 z-20 mt-1 max-h-48 overflow-y-auto rounded-lg border bg-white shadow-lg">
                          {searchResults.map((p) => (
                            <button key={p.code} type="button" onMouseDown={() => selectProduct(item.id, p)}
                              className="flex w-full items-center justify-between px-3 py-2 text-xs hover:bg-cream text-right">
                              <span className="font-bold text-navy" dir="ltr">{p.code}</span>
                              <span className="font-bold text-gold tabular-nums">{p.sellPrice.toLocaleString("ar-YE")} ر.ي</span>
                            </button>
                          ))}
                        </div>
                      )}
                    </div>
                    <div className="col-span-7 sm:col-span-3">
                      <label className="mb-1 block text-[10px] font-medium text-gray-400">المنتج</label>
                      <input value={item.productName} readOnly className="w-full rounded-lg border border-gray-200 bg-gray-50 px-3 py-2 text-sm text-gray-600" placeholder="سيظهر تلقائياً" />
                    </div>
                    <div className="col-span-3 sm:col-span-1">
                      <label className="mb-1 block text-[10px] font-medium text-gray-400">الكمية</label>
                      <input type="number" min="1" value={item.quantity}
                        onChange={(e) => updateItemField(item.id, "quantity", parseInt(e.target.value) || 1)}
                        className="w-full rounded-lg border border-gray-200 px-2 py-2 text-sm text-center focus:border-gold focus:outline-none" />
                    </div>
                    <div className="col-span-4 sm:col-span-2">
                      <label className="mb-1 block text-[10px] font-medium text-gray-400">سعر البيع</label>
                      <input type="number" value={item.unitPrice}
                        onChange={(e) => updateItemField(item.id, "unitPrice", parseFloat(e.target.value) || 0)}
                        className="w-full rounded-lg border border-gray-200 px-2 py-2 text-sm text-center focus:border-gold focus:outline-none" />
                    </div>
                    <div className="col-span-3 sm:col-span-1 text-center text-xs font-bold text-gold tabular-nums pt-5">
                      {item.total.toLocaleString("ar-YE")}
                    </div>
                    <div className="col-span-2 sm:col-span-1 flex justify-center pt-5">
                      <button type="button" onClick={() => removeItem(item.id)} className="rounded-lg p-1.5 text-red-400 hover:bg-red-50" aria-label="حذف"><Trash2 className="size-4" /></button>
                    </div>
                  </div>
                  {item.buyPrice ? (
                    <div className="mt-1.5 flex items-center gap-2 text-[10px] text-gray-400">
                      <Calculator className="size-3" /> تكلفة: {formatCurrency(item.buyPrice)} · ربح: <span className="text-emerald-600 font-semibold">{formatCurrency(item.unitPrice - item.buyPrice)}</span>
                    </div>
                  ) : null}
                </div>
              ))}
            </div>
          </div>

          <div className="grid grid-cols-3 gap-3 sm:gap-4">
            <div>
              <label className="mb-1.5 block text-sm font-semibold text-gray-700">الخصم</label>
              <input type="number" min="0" value={discount} onChange={(e) => setDiscount(parseFloat(e.target.value) || 0)}
                className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none" />
            </div>
            <div>
              <label className="mb-1.5 block text-sm font-semibold text-gray-700">المدفوع</label>
              <input type="number" min="0" value={paid} onChange={(e) => setPaid(parseFloat(e.target.value) || 0)}
                className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none" />
            </div>
            <div className="flex flex-col justify-end">
              <div className="rounded-xl bg-navy/5 p-2.5 text-center">
                <p className="text-[10px] text-gray-500">الإجمالي</p>
                <p className="text-base font-bold text-navy tabular-nums">{total.toLocaleString("ar-YE")} ر.ي</p>
                {remaining > 0 && <p className="text-[10px] text-red-500">متبقي: {remaining.toLocaleString("ar-YE")}</p>}
              </div>
            </div>
          </div>

          <div>
            <label className="mb-1.5 block text-sm font-semibold text-gray-700">ملاحظات</label>
            <textarea value={notes} onChange={(e) => setNotes(e.target.value)} rows={2}
              className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none resize-none" />
          </div>
        </div>
        <div className="sticky bottom-0 flex gap-3 border-t bg-gray-50 px-4 py-3 rounded-b-2xl sm:px-6 sm:py-4">
          <button onClick={handleSubmit} className="flex-1 rounded-xl bg-navy py-3 text-sm font-bold text-white hover:bg-navy-light active:scale-[0.98]">حفظ الطلب</button>
          <button onClick={onClose} className="rounded-xl border border-gray-200 bg-white px-6 py-3 text-sm font-semibold text-gray-600 hover:bg-gray-50">إلغاء</button>
        </div>
      </div>
    </div>
  );
}

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
