            <TrendingUp className="size-4 text-navy" /> النشاط اليومي ({daysFilter} يوم)
          </h3>
          <ResponsiveContainer width="100%" height={260}>
            <LineChart data={dailyDistribution}>
              <XAxis dataKey="date" tick={{ fontSize: 10 }} />
              <YAxis tick={{ fontSize: 10 }} />
