import { useEffect, useState } from "react";
import { ShieldCheck, CheckCircle2, XCircle, Clock, Loader2, Filter, AlertCircle, Plus, DollarSign, Package, RotateCcw, Receipt, ArrowRight } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { supabase } from "@/lib/supabase";
import { useAuditStore } from "@/stores/auditStore";
import { formatCurrency, formatDate } from "@/lib/formatters";
import { logActivity } from "@/hooks/useActivityLogger";

interface ApprovalRequest {
  id: string;
  requesterEmail: string;
  requestType: "invoice" | "discount" | "return" | "expense" | "transfer";
  entityId: string;
  amount: number;
  reason: string;
  status: "pending" | "approved" | "rejected";
  reviewedBy: string;
  reviewedAt?: string;
  createdAt: string;
}

const REQUEST_TYPE_META: Record<string, { label: string; icon: typeof Receipt; color: string }> = {
  invoice: { label: "اعتماد فاتورة", icon: Receipt, color: "bg-blue-50 text-blue-700 border-blue-200" },
  discount: { label: "اعتماد خصم", icon: DollarSign, color: "bg-amber-50 text-amber-700 border-amber-200" },
  return: { label: "اعتماد مرتجع", icon: RotateCcw, color: "bg-red-50 text-red-700 border-red-200" },
  expense: { label: "اعتماد مصروف", icon: Receipt, color: "bg-purple-50 text-purple-700 border-purple-200" },
  transfer: { label: "اعتماد تحويل", icon: ArrowRight, color: "bg-cyan-50 text-cyan-700 border-cyan-200" },
};

const STATUS_META: Record<string, { label: string; color: string; icon: typeof Clock }> = {
  pending: { label: "قيد المراجعة", color: "bg-amber-100 text-amber-800", icon: Clock },
  approved: { label: "معتمد", color: "bg-emerald-100 text-emerald-800", icon: CheckCircle2 },
  rejected: { label: "مرفوض", color: "bg-red-100 text-red-800", icon: XCircle },
};

export default function Approvals() {
  const { user } = useAuth();
  const { logAction } = useAuditStore();
  const [requests, setRequests] = useState<ApprovalRequest[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<"all" | "pending" | "approved" | "rejected">("pending");
  const [showForm, setShowForm] = useState(false);
  const [processing, setProcessing] = useState<string | null>(null);

  // New request form
  const [reqType, setReqType] = useState<ApprovalRequest["requestType"]>("discount");
  const [reqAmount, setReqAmount] = useState(0);
  const [reqReason, setReqReason] = useState("");
  const [reqEntityId, setReqEntityId] = useState("");

  useEffect(() => { loadRequests(); }, [user?.id, filter]);

  const loadRequests = async () => {
    if (!user?.id) return;
    setLoading(true);
    let query = supabase.from("approval_requests").select("*").eq("user_id", user.id).order("created_at", { ascending: false });
    if (filter !== "all") query = query.eq("status", filter);
    const { data } = await query;
    const mapped: ApprovalRequest[] = (data || []).map((r: {
      id: string; requester_email: string; request_type: string; entity_id: string;
      amount: string; reason: string; status: string; reviewed_by: string;
      reviewed_at: string | null; created_at: string;
    }) => ({
      id: r.id,
      requesterEmail: r.requester_email,
      requestType: r.request_type as ApprovalRequest["requestType"],
      entityId: r.entity_id,
      amount: Number(r.amount),
      reason: r.reason,
      status: r.status as ApprovalRequest["status"],
      reviewedBy: r.reviewed_by,
      reviewedAt: r.reviewed_at || undefined,
      createdAt: r.created_at,
    }));
    setRequests(mapped);
    setLoading(false);
  };

  const handleCreateRequest = async () => {
    if (!user?.id) return;
    if (!reqReason.trim()) { toast.error("أدخل سبب الطلب"); return; }
    if (reqAmount <= 0) { toast.error("أدخل مبلغاً صحيحاً"); return; }

    const { error } = await supabase.from("approval_requests").insert({
      user_id: user.id,
      requester_email: user.email,
      request_type: reqType,
      entity_id: reqEntityId,
      amount: reqAmount,
      reason: reqReason,
      status: "pending",
    });

    if (error) { toast.error("فشل: " + error.message); return; }
    logAction(user.id, "create", "approval", undefined, `طلب ${REQUEST_TYPE_META[reqType].label}: ${formatCurrency(reqAmount)}`);
    logActivity(user.email, user.id, "action", `إنشاء طلب اعتماد: ${REQUEST_TYPE_META[reqType].label}`, { entityType: "approval" });
    toast.success("تم إنشاء طلب الاعتماد");
    setShowForm(false);
    setReqAmount(0); setReqReason(""); setReqEntityId("");
    loadRequests();
  };

  const handleDecision = async (req: ApprovalRequest, decision: "approved" | "rejected") => {
    if (!user?.id) return;
    if (!confirm(`${decision === "approved" ? "اعتماد" : "رفض"} هذا الطلب؟`)) return;
    setProcessing(req.id);
    const { error } = await supabase.from("approval_requests").update({
      status: decision,
      reviewed_by: user.email,
      reviewed_at: new Date().toISOString(),
    }).eq("id", req.id);

    if (error) { toast.error("فشل: " + error.message); setProcessing(null); return; }
    logAction(user.id, "status_change", "approval", req.id, `${decision === "approved" ? "اعتماد" : "رفض"} طلب ${REQUEST_TYPE_META[req.requestType].label} من ${req.requesterEmail}`);
    logActivity(user.email, user.id, "action", `${decision === "approved" ? "اعتماد" : "رفض"} طلب`, { entityType: "approval", entityId: req.id });
    toast.success(decision === "approved" ? "✅ تم الاعتماد" : "❌ تم الرفض");
    loadRequests();
    setProcessing(null);
  };

  const pendingCount = requests.filter((r) => r.status === "pending").length;
  const approvedCount = requests.filter((r) => r.status === "approved").length;
  const rejectedCount = requests.filter((r) => r.status === "rejected").length;

  return (
    <div className="space-y-4 lg:space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl flex items-center gap-2">
            <ShieldCheck className="size-5 text-indigo-600" /> نظام الموافقات (Approval Workflow)
          </h1>
          <p className="text-xs text-gray-500 sm:text-sm">اعتماد العمليات الحساسة قبل تنفيذها</p>
        </div>
        <button onClick={() => setShowForm(!showForm)}
          className="flex items-center gap-2 rounded-xl bg-navy px-4 py-2.5 text-sm font-bold text-white hover:bg-navy-light shadow-lg">
          <Plus className="size-4" /> طلب اعتماد جديد
        </button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-3">
        <div className="rounded-2xl bg-amber-50 border border-amber-200 p-4">
          <Clock className="size-4 text-amber-600 mb-1" />
          <p className="text-xs text-amber-700 font-semibold">قيد المراجعة</p>
          <p className="text-2xl font-bold text-amber-800 tabular-nums">{pendingCount}</p>
        </div>
        <div className="rounded-2xl bg-emerald-50 border border-emerald-200 p-4">
          <CheckCircle2 className="size-4 text-emerald-600 mb-1" />
          <p className="text-xs text-emerald-700 font-semibold">معتمد</p>
          <p className="text-2xl font-bold text-emerald-800 tabular-nums">{approvedCount}</p>
        </div>
        <div className="rounded-2xl bg-red-50 border border-red-200 p-4">
          <XCircle className="size-4 text-red-600 mb-1" />
          <p className="text-xs text-red-700 font-semibold">مرفوض</p>
          <p className="text-2xl font-bold text-red-800 tabular-nums">{rejectedCount}</p>
        </div>
      </div>

      {/* Info */}
      <div className="rounded-2xl bg-indigo-50 border border-indigo-200 p-4">
        <div className="flex items-start gap-3">
          <AlertCircle className="size-5 text-indigo-600 shrink-0 mt-0.5" />
          <div className="text-sm text-indigo-900">
            <p className="font-bold mb-1">💡 آلية الاعتماد:</p>
            <ul className="text-xs list-disc list-inside space-y-0.5">
              <li>أي عملية حساسة (خصم، مرتجع، مصروف كبير) تُرسل للاعتماد قبل التنفيذ</li>
              <li>المسؤول يستعرض التفاصيل ويوافق أو يرفض مع تسجيل قراره</li>
              <li>جميع القرارات مسجّلة في سجل التدقيق</li>
              <li>لا يتم تنفيذ العملية تلقائياً بعد الاعتماد - يتم يدوياً من الصفحة المعنية</li>
            </ul>
          </div>
        </div>
      </div>

      {/* New request form */}
      {showForm && (
        <div className="rounded-2xl bg-white p-5 border-2 border-navy shadow-lg space-y-3">
          <h3 className="text-sm font-bold text-navy">📝 طلب اعتماد جديد</h3>
          <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
            <div>
              <label className="text-xs font-bold text-gray-700 mb-1 block">نوع الطلب</label>
              <select value={reqType} onChange={(e) => setReqType(e.target.value as ApprovalRequest["requestType"])}
                className="w-full rounded-xl border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none">
                {Object.entries(REQUEST_TYPE_META).map(([key, meta]) => (
                  <option key={key} value={key}>{meta.label}</option>
                ))}
              </select>
            </div>
            <div>
              <label className="text-xs font-bold text-gray-700 mb-1 block">المبلغ (ر.ي)</label>
              <input type="number" value={reqAmount || ""} onChange={(e) => setReqAmount(parseFloat(e.target.value) || 0)}
                className="w-full rounded-xl border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none tabular-nums"
                placeholder="0" />
            </div>
            <div>
              <label className="text-xs font-bold text-gray-700 mb-1 block">رقم المرجع (اختياري)</label>
              <input value={reqEntityId} onChange={(e) => setReqEntityId(e.target.value)}
                className="w-full rounded-xl border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none"
                placeholder="ORD-001" dir="ltr" />
            </div>
            <div className="sm:col-span-2">
              <label className="text-xs font-bold text-gray-700 mb-1 block">السبب/التبرير</label>
              <textarea value={reqReason} onChange={(e) => setReqReason(e.target.value)} rows={2}
                className="w-full rounded-xl border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none resize-none"
                placeholder="اشرح سبب الطلب..." />
            </div>
          </div>
          <div className="flex gap-2">
            <button onClick={handleCreateRequest}
              className="flex-1 rounded-xl bg-navy text-white py-2.5 text-sm font-bold hover:bg-navy-light">
              إرسال الطلب
            </button>
            <button onClick={() => setShowForm(false)}
              className="rounded-xl border border-gray-200 px-4 py-2.5 text-sm font-bold text-gray-600 hover:bg-gray-50">
              إلغاء
            </button>
          </div>
        </div>
      )}

      {/* Filter */}
      <div className="flex items-center gap-2 flex-wrap">
        <Filter className="size-4 text-gray-500" />
        {(["all", "pending", "approved", "rejected"] as const).map((f) => (
          <button key={f} onClick={() => setFilter(f)}
            className={`rounded-xl px-4 py-1.5 text-xs font-bold transition-colors ${
              filter === f ? "bg-navy text-white" : "bg-white border border-gray-200 text-gray-600 hover:bg-cream/50"
            }`}>
            {f === "all" ? "الكل" : STATUS_META[f].label}
          </button>
        ))}
      </div>

      {/* Requests list */}
      {loading ? (
        <div className="flex items-center justify-center py-12"><Loader2 className="size-6 animate-spin text-navy" /></div>
      ) : requests.length === 0 ? (
        <div className="rounded-2xl border-2 border-dashed border-gray-300 bg-white p-12 text-center">
          <ShieldCheck className="mx-auto size-10 text-gray-300 mb-2" />
          <p className="text-sm text-gray-500">لا توجد طلبات اعتماد {filter !== "all" ? `بحالة "${STATUS_META[filter].label}"` : ""}</p>
        </div>
      ) : (
        <div className="space-y-2">
          {requests.map((req) => {
            const typeMeta = REQUEST_TYPE_META[req.requestType];
            const statusMeta = STATUS_META[req.status];
            const TypeIcon = typeMeta.icon;
            const StatusIcon = statusMeta.icon;
            return (
              <div key={req.id} className={`rounded-2xl border p-4 bg-white shadow-sm ${req.status === "pending" ? "border-amber-200" : "border-gray-100"}`}>
                <div className="flex items-start justify-between flex-wrap gap-3">
                  <div className="flex items-start gap-3 flex-1 min-w-0">
                    <div className={`rounded-xl p-2.5 border ${typeMeta.color}`}>
                      <TypeIcon className="size-5" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <p className="text-sm font-bold text-navy">{typeMeta.label}</p>
                        <span className={`inline-flex items-center gap-1 rounded-full px-2 py-0.5 text-[10px] font-bold ${statusMeta.color}`}>
                          <StatusIcon className="size-3" /> {statusMeta.label}
                        </span>
                        {req.entityId && (
                          <span className="text-[10px] font-mono bg-gray-100 rounded px-1.5 py-0.5" dir="ltr">{req.entityId}</span>
                        )}
                      </div>
                      <p className="text-xs text-gray-600 mt-1 line-clamp-2">{req.reason}</p>
                      <div className="flex items-center gap-3 mt-2 text-[10px] text-gray-500 flex-wrap">
                        <span>مقدّم من: <b dir="ltr">{req.requesterEmail}</b></span>
                        <span>·</span>
                        <span>{formatDate(req.createdAt)}</span>
                        {req.reviewedBy && (
                          <>
                            <span>·</span>
                            <span>راجعه: <b dir="ltr">{req.reviewedBy}</b></span>
                          </>
                        )}
                      </div>
                    </div>
                  </div>
                  <div className="flex flex-col items-end gap-2">
                    <p className="text-lg font-bold text-navy tabular-nums">{formatCurrency(req.amount)}</p>
                    {req.status === "pending" && (
                      <div className="flex gap-1.5">
                        <button onClick={() => handleDecision(req, "approved")} disabled={processing === req.id}
                          className="flex items-center gap-1 rounded-lg bg-emerald-500 text-white px-3 py-1.5 text-xs font-bold hover:bg-emerald-600 disabled:opacity-50">
                          {processing === req.id ? <Loader2 className="size-3 animate-spin" /> : <CheckCircle2 className="size-3" />} اعتماد
                        </button>
                        <button onClick={() => handleDecision(req, "rejected")} disabled={processing === req.id}
                          className="flex items-center gap-1 rounded-lg bg-red-500 text-white px-3 py-1.5 text-xs font-bold hover:bg-red-600 disabled:opacity-50">
                          <XCircle className="size-3" /> رفض
                        </button>
                      </div>
                    )}
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

import { useEffect, useState } from "react";
import { ClipboardList, Search, Filter, Clock, User, Edit, Trash2, CreditCard, LogIn, Send, Settings, RefreshCw } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { useAuditStore } from "@/stores/auditStore";
import { getAuditActionLabel, getEntityTypeLabel, formatDate } from "@/lib/formatters";

const ACTION_ICONS: Record<string, typeof Edit> = {
  create: Edit, update: Edit, delete: Trash2, status_change: RefreshCw,
  payment: CreditCard, login: LogIn, export: Send, settings_update: Settings, bulk_whatsapp: Send,
};

const ACTION_COLORS: Record<string, string> = {
  create: "bg-emerald-50 text-emerald-600", update: "bg-blue-50 text-blue-600",
  delete: "bg-red-50 text-red-600", status_change: "bg-amber-50 text-amber-600",
  payment: "bg-indigo-50 text-indigo-600", login: "bg-gray-50 text-gray-600",
  export: "bg-purple-50 text-purple-600", settings_update: "bg-cyan-50 text-cyan-600",
  bulk_whatsapp: "bg-emerald-50 text-emerald-600",
};

export default function AuditLogs() {
  const { user } = useAuth();
  const { logs, loading, initializeLogs } = useAuditStore();
  const [search, setSearch] = useState("");
  const [actionFilter, setActionFilter] = useState("all");

  useEffect(() => { if (user?.id) initializeLogs(user.id); }, [user?.id]);

  const filtered = logs.filter((log) => {
    const matchSearch = !search || log.details.includes(search) || log.entityType.includes(search) || log.action.includes(search);
    const matchAction = actionFilter === "all" || log.action === actionFilter;
    return matchSearch && matchAction;
  });

  return (
    <div className="space-y-4 lg:space-y-6">
      <div>
        <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl">سجل الأحداث</h1>
        <p className="text-xs text-gray-500 sm:text-sm">تتبع جميع العمليات والتغييرات في النظام</p>
      </div>

      <div className="flex flex-col gap-2 rounded-2xl bg-white p-3 shadow-sm border border-gray-100 sm:flex-row sm:gap-3 sm:p-4">
        <div className="relative flex-1">
          <Search className="absolute right-3 top-1/2 size-4 -translate-y-1/2 text-gray-400" />
          <input type="text" value={search} onChange={(e) => setSearch(e.target.value)}
            className="w-full rounded-xl border border-gray-200 py-2.5 pe-4 ps-10 text-sm focus:border-gold focus:outline-none focus:ring-2 focus:ring-gold/20"
            placeholder="بحث في السجل..." />
        </div>
        <select value={actionFilter} onChange={(e) => setActionFilter(e.target.value)}
          className="rounded-xl border border-gray-200 bg-white py-2.5 px-3 text-xs focus:border-gold focus:outline-none sm:text-sm">
          <option value="all">كل العمليات</option>
          <option value="create">إنشاء</option>
          <option value="update">تعديل</option>
          <option value="delete">حذف</option>
          <option value="status_change">تغيير حالة</option>
          <option value="payment">دفعة</option>
          <option value="export">تصدير</option>
          <option value="settings_update">إعدادات</option>
          <option value="bulk_whatsapp">واتساب جماعي</option>
        </select>
      </div>

      <div className="space-y-2">
        {filtered.map((log, idx) => {
          const Icon = ACTION_ICONS[log.action] || ClipboardList;
          const color = ACTION_COLORS[log.action] || "bg-gray-50 text-gray-600";
          return (
            <div key={log.id} className="flex items-start gap-3 rounded-2xl bg-white p-4 shadow-sm border border-gray-100 animate-fade-in opacity-0"
              style={{ animationDelay: `${idx * 30}ms` }}>
              <div className={`rounded-xl p-2.5 shrink-0 ${color}`}>
                <Icon className="size-4" />
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 flex-wrap">
                  <span className="text-sm font-bold text-navy">{getAuditActionLabel(log.action)}</span>
                  <span className="rounded-lg bg-cream px-2 py-0.5 text-[10px] font-semibold text-gray-600">
                    {getEntityTypeLabel(log.entityType)}
                  </span>
                  {log.entityId && <span className="text-[10px] text-gray-400" dir="ltr">{log.entityId.slice(0, 8)}...</span>}
                </div>
                <p className="text-xs text-gray-500 mt-0.5 line-clamp-2">{log.details}</p>
              </div>
              <div className="shrink-0 text-left">
                <p className="text-[10px] text-gray-400 flex items-center gap-1">
                  <Clock className="size-3" />
                  {new Date(log.createdAt).toLocaleDateString("ar-SA", { month: "short", day: "numeric" })}
                </p>
                <p className="text-[10px] text-gray-300">
                  {new Date(log.createdAt).toLocaleTimeString("ar-SA", { hour: "2-digit", minute: "2-digit" })}
                </p>
              </div>
            </div>
          );
        })}
      </div>

      {filtered.length === 0 && !loading && (
        <div className="flex flex-col items-center gap-4 py-20">
          <div className="rounded-full bg-gray-50 p-6"><ClipboardList className="size-10 text-gray-300" /></div>
          <h3 className="text-lg font-bold text-navy">لا توجد سجلات</h3>
          <p className="text-sm text-gray-400">سيتم تسجيل جميع العمليات هنا تلقائياً</p>
        </div>
      )}
    </div>
  );
}

import { useState, useMemo, useEffect } from "react";
import { Link } from "react-router-dom";
import { Plus, Search, Phone, MapPin, Trash2, UserCircle, MessageCircle, Clock, User2, Filter, X, ExternalLink, PhoneCall } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { useDataStore } from "@/stores/dataStore";
import { useNotificationStore } from "@/stores/notificationStore";
import { formatCurrency } from "@/lib/formatters";
import CustomerFormDialog from "@/components/features/CustomerFormDialog";
import WhatsAppButton from "@/components/features/WhatsAppButton";
import CustomerWhatsAppHistory from "@/components/features/CustomerWhatsAppHistory";
import { WHATSAPP_TEMPLATES } from "@/constants/config";

const SOURCE_LABELS: Record<string, string> = {
  whatsapp: "واتساب 💬",
  instagram: "إنستقرام 📸",
  facebook: "فيسبوك 📘",
  direct: "مباشر 🏪",
  referral: "توصية 🤝",
  other: "أخرى",
};

const SOURCE_OPTIONS = [
  { value: "", label: "الكل" },
  { value: "whatsapp", label: "واتساب" },
  { value: "instagram", label: "إنستقرام" },
  { value: "facebook", label: "فيسبوك" },
  { value: "direct", label: "مباشر" },
  { value: "referral", label: "توصية" },
  { value: "other", label: "أخرى" },
];

export default function Customers() {
  const { user, role } = useAuth();
  const { customers, orders, initializeData, deleteCustomer, getCustomerDebt } = useDataStore();
  const { notifications, initializeData: initNotifications } = useNotificationStore();
  const [search, setSearch] = useState("");
  const [showForm, setShowForm] = useState(false);
  const [historyTarget, setHistoryTarget] = useState<{ name: string; phone: string } | null>(null);
  const [sourceFilter, setSourceFilter] = useState("");
  const [repFilter, setRepFilter] = useState("");
  const [showFilters, setShowFilters] = useState(false);

  useEffect(() => {
    if (user?.id) {
      initializeData(user.id);
      initNotifications(user.id);
    }
  }, [user?.id]);

  // Get unique rep names for filter
  const repNames = useMemo(() => {
    const names = new Set<string>();
    customers.forEach((c) => {
      if ((c as any).addedByName) names.add((c as any).addedByName);
    });
    return Array.from(names);
  }, [customers]);

  const filtered = useMemo(() => {
    return customers.filter((c) => {
      const matchSearch = !search || c.name.includes(search) || c.phone.includes(search) || c.city.includes(search);
      const matchSource = !sourceFilter || (c as any).source === sourceFilter;
      const matchRep = !repFilter || (c as any).addedByName === repFilter;
      return matchSearch && matchSource && matchRep;
    });
  }, [customers, search, sourceFilter, repFilter]);

  const getOrderCount = (customerId: string) => orders.filter((o) => o.customerId === customerId).length;
  const getTotalSpent = (customerId: string) => orders.filter((o) => o.customerId === customerId).reduce((s, o) => s + o.total, 0);

  const getLastContact = (phone: string) => {
    const cleaned = phone.replace(/\D/g, "");
    const msg = notifications.find((n) => {
      const nPhone = n.recipientPhone.replace(/\D/g, "");
      return nPhone === cleaned || nPhone.endsWith(cleaned.slice(-9)) || cleaned.endsWith(nPhone.slice(-9));
    });
    if (!msg) return null;
    const d = new Date(msg.sentAt);
    const now = new Date();
    const diffDays = Math.floor((now.getTime() - d.getTime()) / (1000 * 60 * 60 * 24));
    if (diffDays === 0) return "اليوم";
    if (diffDays === 1) return "أمس";
    if (diffDays < 7) return `منذ ${diffDays} أيام`;
    return d.toLocaleDateString("ar-SA", { month: "short", day: "numeric" });
  };

  const getMessageCount = (phone: string) => {
    const cleaned = phone.replace(/\D/g, "");
    return notifications.filter((n) => {
      const nPhone = n.recipientPhone.replace(/\D/g, "");
      return nPhone === cleaned || nPhone.endsWith(cleaned.slice(-9)) || cleaned.endsWith(nPhone.slice(-9));
    }).length;
  };

  const handleDelete = (id: string, name: string) => {
    if (role !== "admin") { toast.error("ليس لديك صلاحية الحذف"); return; }
    if (window.confirm(`هل أنت متأكد من حذف العميل "${name}"؟`)) { deleteCustomer(id); toast.success("تم حذف العميل"); }
  };

  const isReadOnly = role === "support";
  const hasActiveFilters = sourceFilter || repFilter;
  const invalidPhones = customers.filter((c) => {
    const cleaned = c.phone.replace(/\D/g, "");
    return cleaned.length < 9;
  }).length;

  return (
    <div className="space-y-4 lg:space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl">إدارة العملاء</h1>
          <p className="text-xs text-gray-500 sm:text-sm">{filtered.length} من {customers.length} عميل</p>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          {role === "admin" && invalidPhones > 0 && (
            <Link to="/phone-validator"
              className="flex items-center gap-2 rounded-xl bg-red-50 border border-red-200 px-3 py-2 text-xs font-semibold text-red-600 hover:bg-red-100">
              <PhoneCall className="size-3.5" /> فحص {invalidPhones} رقم خاطئ
            </Link>
          )}
          <button onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center gap-2 rounded-xl border px-4 py-2.5 text-sm font-semibold transition-colors ${hasActiveFilters ? "border-gold bg-gold/10 text-gold-dark" : "border-gray-200 text-gray-600 hover:bg-gray-50"}`}>
            <Filter className="size-4" /> تصفية
            {hasActiveFilters && <span className="flex size-5 items-center justify-center rounded-full bg-gold text-[10px] font-bold text-white">{(sourceFilter ? 1 : 0) + (repFilter ? 1 : 0)}</span>}
          </button>
          {!isReadOnly && (
            <button onClick={() => setShowForm(true)}
              className="flex items-center justify-center gap-2 rounded-xl bg-navy px-5 py-2.5 text-sm font-bold text-white shadow-lg shadow-navy/20 transition-all hover:bg-navy-light active:scale-[0.98]">
              <Plus className="size-4" /> عميل جديد
            </button>
          )}
        </div>
      </div>

      {/* Filters Panel */}
      {showFilters && (
        <div className="rounded-2xl bg-white p-4 shadow-sm border border-gray-100 animate-fade-in space-y-3">
          <div className="flex items-center justify-between">
            <h3 className="text-sm font-bold text-navy">تصفية العملاء</h3>
            {hasActiveFilters && (
              <button onClick={() => { setSourceFilter(""); setRepFilter(""); }}
                className="flex items-center gap-1 text-xs font-semibold text-red-500 hover:text-red-700">
                <X className="size-3" /> مسح الفلاتر
              </button>
            )}
          </div>
          <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
            <div>
              <label className="mb-1.5 block text-xs font-semibold text-gray-600">المصدر (Lead Source)</label>
              <select value={sourceFilter} onChange={(e) => setSourceFilter(e.target.value)}
                className="w-full rounded-xl border border-gray-200 bg-white px-4 py-2.5 text-sm focus:border-gold focus:outline-none">
                {SOURCE_OPTIONS.map((s) => <option key={s.value} value={s.value}>{s.label}</option>)}
              </select>
            </div>
            <div>
              <label className="mb-1.5 block text-xs font-semibold text-gray-600">المندوب</label>
              <select value={repFilter} onChange={(e) => setRepFilter(e.target.value)}
                className="w-full rounded-xl border border-gray-200 bg-white px-4 py-2.5 text-sm focus:border-gold focus:outline-none">
                <option value="">جميع المناديب</option>
                {repNames.map((name) => <option key={name} value={name}>{name}</option>)}
              </select>
            </div>
          </div>
        </div>
      )}

      <div className="relative max-w-md">
        <Search className="absolute right-3 top-1/2 size-4 -translate-y-1/2 text-gray-400" />
        <input type="text" value={search} onChange={(e) => setSearch(e.target.value)}
          className="w-full rounded-xl border border-gray-200 bg-white py-2.5 pe-4 ps-10 text-sm shadow-sm focus:border-gold focus:outline-none focus:ring-2 focus:ring-gold/20"
          placeholder="بحث بالاسم أو الهاتف أو المدينة..." />
      </div>

      <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 xl:grid-cols-3 sm:gap-4">
        {filtered.map((customer, idx) => {
          const debt = getCustomerDebt(customer.id);
          const orderCount = getOrderCount(customer.id);
          const totalSpent = getTotalSpent(customer.id);
          const lastContact = getLastContact(customer.phone);
          const msgCount = getMessageCount(customer.phone);
          return (
            <div key={customer.id}
              className="group rounded-2xl bg-white p-4 shadow-sm border border-gray-100 hover:shadow-md transition-shadow animate-fade-in opacity-0 sm:p-5"
              style={{ animationDelay: `${idx * 40}ms` }}>
              <div className="flex items-start justify-between mb-3">
                <Link to={`/customers/${customer.id}`} className="flex items-center gap-2.5 flex-1 min-w-0 hover:text-gold transition-colors">
                  <div className="flex size-10 items-center justify-center rounded-full bg-gradient-to-bl from-navy to-navy-light text-xs font-bold text-white shrink-0">
                    {customer.name.charAt(0)}
                  </div>
                  <div className="min-w-0">
                    <h3 className="text-sm font-bold text-navy flex items-center gap-1 truncate">{customer.name} <ExternalLink className="size-3 text-gray-300" /></h3>
                    <div className="flex items-center gap-1 text-[10px] text-gray-400">
                      <MapPin className="size-3" /> {customer.city || "—"}
                    </div>
                  </div>
                </Link>
                <div className="flex items-center gap-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity">
                  <WhatsAppButton phone={customer.phone} message={WHATSAPP_TEMPLATES.thankYou(customer.name)} />
                  {role === "admin" && (
                    <button onClick={() => handleDelete(customer.id, customer.name)}
                      className="inline-flex size-8 items-center justify-center rounded-lg text-red-400 hover:bg-red-50 hover:text-red-600 transition-colors" aria-label="حذف">
                      <Trash2 className="size-4" />
                    </button>
                  )}
                </div>
              </div>

              <div className="flex items-center gap-2 mb-2 text-xs text-gray-500">
                <Phone className="size-3" /> <span dir="ltr">{customer.phone}</span>
              </div>

              {/* Source & Added by info */}
              <div className="flex flex-wrap items-center gap-1.5 mb-2">
                {(customer as any).source && (
                  <span className="text-[10px] font-semibold bg-blue-50 text-blue-700 rounded px-1.5 py-0.5">
                    {SOURCE_LABELS[(customer as any).source] || (customer as any).source}
                  </span>
                )}
                {(customer as any).addedByName && (
                  <span className="text-[10px] font-semibold bg-purple-50 text-purple-700 rounded px-1.5 py-0.5 flex items-center gap-0.5">
                    <User2 className="size-2.5" /> {(customer as any).addedByName}
                  </span>
                )}
              </div>

              {/* WhatsApp history summary */}
              <div className="flex items-center justify-between mb-3 rounded-lg bg-emerald-50/60 px-3 py-2">
                <div className="flex items-center gap-1.5">
                  <MessageCircle className="size-3 text-emerald-600" />
                  <span className="text-[10px] font-semibold text-emerald-700">{msgCount} رسالة</span>
                  {lastContact && (
                    <span className="text-[9px] text-gray-400 flex items-center gap-0.5">
                      <Clock className="size-2.5" /> {lastContact}
                    </span>
                  )}
                </div>
                {msgCount > 0 && (
                  <button onClick={() => setHistoryTarget({ name: customer.name, phone: customer.phone })}
                    className="text-[10px] font-semibold text-emerald-700 hover:text-emerald-800 hover:underline">
                    عرض السجل
                  </button>
                )}
              </div>

              <div className="grid grid-cols-3 gap-2 rounded-xl bg-cream/60 p-2.5 sm:p-3">
                <div className="text-center">
                  <p className="text-[10px] text-gray-400">الطلبات</p>
                  <p className="text-xs font-bold text-navy tabular-nums sm:text-sm">{orderCount}</p>
                </div>
                <div className="text-center border-x border-gray-200">
                  <p className="text-[10px] text-gray-400">الإنفاق</p>
                  <p className="text-[10px] font-bold text-gold tabular-nums sm:text-xs">
                    {role === "admin" ? (totalSpent > 0 ? formatCurrency(totalSpent) : "—") : "—"}
                  </p>
                </div>
                <div className="text-center">
                  <p className="text-[10px] text-gray-400">المديونية</p>
                  <p className={`text-xs font-bold tabular-nums sm:text-sm ${debt > 0 ? "text-red-600" : "text-green-600"}`}>
                    {role === "admin" ? (debt > 0 ? formatCurrency(debt) : "لا يوجد") : "—"}
                  </p>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div className="flex flex-col items-center gap-3 py-16">
          <UserCircle className="size-12 text-gray-300" />
          <p className="text-sm text-gray-400">
            {hasActiveFilters ? "لا يوجد عملاء مطابقون لهذه الفلاتر" : "لا يوجد عملاء — أضف أول عميل"}
          </p>
        </div>
      )}

      <CustomerFormDialog open={showForm} onClose={() => setShowForm(false)} />
      {historyTarget && (
        <CustomerWhatsAppHistory open onClose={() => setHistoryTarget(null)}
          customerName={historyTarget.name} customerPhone={historyTarget.phone} />
      )}
    </div>
  );
}

import { useEffect } from "react";
import { useState } from "react";
import { AlertTriangle, DollarSign, Users, CreditCard, ChevronDown, ChevronUp, Landmark, Send, MessageCircle } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { useDataStore } from "@/stores/dataStore";
import { formatCurrency, formatDate, getStatusLabel, getStatusColor } from "@/lib/formatters";
import StatCard from "@/components/features/StatCard";
import WhatsAppButton from "@/components/features/WhatsAppButton";
import PaymentDialog from "@/components/features/PaymentDialog";
import BulkWhatsAppDialog from "@/components/features/BulkWhatsAppDialog";
import { WHATSAPP_TEMPLATES } from "@/constants/config";

export default function Debts() {
  const { user } = useAuth();
  const { getDebtors, getTotalDebt, orders, initializeData } = useDataStore();
  useEffect(() => { if (user?.id) initializeData(user.id); }, [user?.id]);

  const debtors = getDebtors();
  const totalDebt = getTotalDebt();
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [paymentTarget, setPaymentTarget] = useState<{ orderId: string; customerId: string; customerName: string; remaining: number } | null>(null);
  const [showBulk, setShowBulk] = useState(false);
  const unpaidOrders = orders.filter((o) => o.paymentStatus === "unpaid").length;
  const partialOrders = orders.filter((o) => o.paymentStatus === "partial").length;

  return (
    <div className="space-y-4 lg:space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl">تتبع المديونيات</h1>
          <p className="text-xs text-gray-500 sm:text-sm">إجمالي بالسعودي: {formatCurrency(totalDebt, "SAR")}</p>
        </div>
        {debtors.length > 0 && (
          <button onClick={() => setShowBulk(true)}
            className="flex items-center gap-2 rounded-xl bg-emerald-500 px-5 py-3 text-sm font-bold text-white shadow-lg shadow-emerald-500/20 hover:bg-emerald-600 transition-all active:scale-[0.98]">
            <MessageCircle className="size-4" /> مطالبة الكل بالواتساب ({debtors.length})
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 gap-3 sm:grid-cols-3 sm:gap-4">
        <StatCard title="إجمالي المديونيات" value={formatCurrency(totalDebt)} icon={AlertTriangle} trend={formatCurrency(totalDebt, "SAR")} delay={3} />
        <StatCard title="عدد المدينين" value={`${debtors.length} عميل`} icon={Users} delay={0} />
        <StatCard title="طلبات غير مدفوعة" value={`${unpaidOrders + partialOrders} طلب`} icon={DollarSign} trend={`${unpaidOrders} غير مدفوع · ${partialOrders} جزئي`} delay={1} />
      </div>
      <div className="space-y-3">
        {debtors.map((debtor, idx) => {
          const isExpanded = expandedId === debtor.customer.id;
          return (
            <div key={debtor.customer.id} className="rounded-2xl bg-white shadow-sm border border-gray-100 overflow-hidden animate-fade-in opacity-0" style={{ animationDelay: `${idx * 60}ms` }}>
              <div className="flex items-center justify-between p-4 cursor-pointer hover:bg-cream/30 transition-colors sm:p-5" onClick={() => setExpandedId(isExpanded ? null : debtor.customer.id)}>
                <div className="flex items-center gap-3">
                  <div className="flex size-10 items-center justify-center rounded-full bg-red-50 text-sm font-bold text-red-600 sm:size-12 sm:text-lg">{debtor.customer.name.charAt(0)}</div>
                  <div>
                    <h3 className="text-sm font-bold text-navy">{debtor.customer.name}</h3>
                    <p className="text-[10px] text-gray-400 sm:text-xs">{debtor.customer.city} · {debtor.orders.length} طلبات</p>
                  </div>
                </div>
                <div className="flex items-center gap-2 sm:gap-3">
                  <div className="text-left">
                    <p className="text-sm font-bold text-red-600 tabular-nums sm:text-lg">{formatCurrency(debtor.debt)}</p>
                    <p className="text-[10px] text-gray-400">{formatCurrency(debtor.debt, "SAR")}</p>
                  </div>
                  <WhatsAppButton phone={debtor.customer.phone} message={WHATSAPP_TEMPLATES.paymentReminder(debtor.customer.name, debtor.debt)} />
                  {isExpanded ? <ChevronUp className="size-5 text-gray-400" /> : <ChevronDown className="size-5 text-gray-400" />}
                </div>
              </div>
              {isExpanded && (
                <div className="border-t bg-cream/20 p-4 space-y-3 sm:p-5">
                  {debtor.orders.map((order) => (
                    <div key={order.id} className="flex flex-col gap-3 rounded-xl bg-white p-3 border border-gray-100 sm:flex-row sm:items-center sm:justify-between sm:p-4">
                      <div className="flex items-center gap-3">
                        <div className="rounded-lg bg-navy/5 p-2"><Landmark className="size-4 text-navy" /></div>
                        <div>
                          <p className="text-sm font-semibold text-navy" dir="ltr">{order.orderNumber}</p>
                          <span className={`rounded px-2 py-0.5 text-[10px] font-semibold ${getStatusColor(order.status)}`}>{getStatusLabel(order.status)}</span>
                        </div>
                      </div>
                      <div className="flex items-center justify-between sm:gap-3">
                        <div className="text-left">
                          <p className="text-xs text-gray-400">الإجمالي: {formatCurrency(order.total)}</p>
                          <p className="text-sm font-bold text-red-600 tabular-nums">متبقي: {formatCurrency(order.remaining)}</p>
                        </div>
                        <button onClick={(e) => { e.stopPropagation(); setPaymentTarget({ orderId: order.id, customerId: debtor.customer.id, customerName: debtor.customer.name, remaining: order.remaining }); }}
                          className="flex items-center gap-1.5 rounded-lg bg-emerald-500 px-3 py-2 text-xs font-semibold text-white hover:bg-emerald-600">
                          <CreditCard className="size-3.5" /> تسجيل دفعة
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </div>
      {debtors.length === 0 && (
        <div className="flex flex-col items-center gap-4 py-20">
          <div className="rounded-full bg-green-50 p-6"><DollarSign className="size-10 text-green-500" /></div>
          <h3 className="text-lg font-bold text-navy">لا توجد مديونيات</h3>
          <p className="text-sm text-gray-400">جميع المبالغ مسددة 🎉</p>
        </div>
      )}
      {paymentTarget && <PaymentDialog open onClose={() => setPaymentTarget(null)} {...paymentTarget} />}
      {showBulk && <BulkWhatsAppDialog open onClose={() => setShowBulk(false)} mode="debtors" />}
    </div>
  );
}

