export default function EmailTemplates() {
  const { user } = useAuth();
  const [templates, setTemplates] = useState<Record<string, EmailTemplate>>({});
  const [selectedKey, setSelectedKey] = useState("welcome");
  const [subject, setSubject] = useState("");
  const [bodyHtml, setBodyHtml] = useState("");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [showPreview, setShowPreview] = useState(true);

  useEffect(() => {
    if (user?.id) loadTemplates();
  }, [user?.id]);

  useEffect(() => {
    const t = templates[selectedKey];
    if (t) {
      setSubject(t.subject);
      setBodyHtml(t.bodyHtml);
    } else {
      const def = DEFAULT_TEMPLATES[selectedKey];
      setSubject(def?.subject || "");
      setBodyHtml(def?.body || "");
    }
  }, [selectedKey, templates]);

  const loadTemplates = async () => {
    if (!user?.id) return;
    const { data } = await supabase.from("email_templates").select("*").eq("user_id", user.id);
    const map: Record<string, EmailTemplate> = {};
    (data || []).forEach((r: { id: string; template_key: string; subject: string; body_html: string; is_active: boolean }) => {
      map[r.template_key] = {
        id: r.id, templateKey: r.template_key, subject: r.subject, bodyHtml: r.body_html, isActive: r.is_active,
      };
    });
    setTemplates(map);
    setLoading(false);
  };

  const handleSave = async () => {
    if (!user?.id) return;
    setSaving(true);
    const { error } = await supabase.from("email_templates").upsert({
      user_id: user.id,
      template_key: selectedKey,
      subject,
      body_html: bodyHtml,
      is_active: true,
      updated_at: new Date().toISOString(),
    }, { onConflict: "user_id,template_key" });
    if (error) { toast.error("فشل الحفظ: " + error.message); setSaving(false); return; }
    toast.success("✅ تم حفظ القالب");
    loadTemplates();
    setSaving(false);
  };

  const handleReset = () => {
    if (!confirm("استعادة القالب الافتراضي؟")) return;
    const def = DEFAULT_TEMPLATES[selectedKey];
    setSubject(def?.subject || "");
    setBodyHtml(def?.body || "");
    toast.success("تم استعادة القالب الافتراضي");
  };

  const insertVariable = (v: string) => {
    setBodyHtml((prev) => prev + v);
    toast.success(`تم إضافة ${v}`);
  };

  // Preview with sample data
  const previewHtml = bodyHtml
    .replace(/{{name}}/g, "أحمد محمد")
    .replace(/{{email}}/g, "ahmed@example.com")
    .replace(/{{password}}/g, "TempPass2026")
    .replace(/{{business_name}}/g, "رداء")
    .replace(/{{amount}}/g, "50,000 ر.ي")
    .replace(/{{date}}/g, new Date().toLocaleDateString("ar-SA"))
    .replace(/{{order_number}}/g, "ORD-2026-001")
    .replace(/{{link}}/g, "#")
    .replace(/{{message}}/g, "لديك إشعار جديد يستحق الاهتمام.");

  if (loading) return <div className="flex items-center justify-center py-20"><Loader2 className="size-8 animate-spin text-navy" /></div>;

  return (
    <div className="space-y-4 lg:space-y-6">
      <div>
        <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl flex items-center gap-2">
          <Mail className="size-5 text-blue-600" /> محرر قوالب البريد الإلكتروني
        </h1>
        <p className="text-xs text-gray-500 sm:text-sm">خصّص جميع الرسائل التي يرسلها النظام</p>
      </div>

      <div className="grid grid-cols-1 gap-4 lg:grid-cols-4">
        {/* Template list */}
        <div className="rounded-2xl bg-white p-3 border border-gray-100 shadow-sm space-y-1">
          <h3 className="text-xs font-bold text-navy mb-2 px-2">📚 القوالب</h3>
          {TEMPLATE_TYPES.map((t) => (
            <button key={t.key} onClick={() => setSelectedKey(t.key)}
              className={`w-full text-right rounded-lg px-3 py-2 text-xs transition-colors ${
                selectedKey === t.key ? "bg-navy text-white" : "hover:bg-cream/50"
              }`}>
              <p className="font-bold">{t.label}</p>
              <p className={`text-[10px] mt-0.5 ${selectedKey === t.key ? "text-white/70" : "text-gray-500"}`}>{t.description}</p>
              {templates[t.key] && (
                <span className={`text-[9px] ${selectedKey === t.key ? "text-emerald-300" : "text-emerald-600"} mt-1 block`}>✅ محفوظ</span>
              )}
            </button>
          ))}
        </div>

        {/* Editor */}
        <div className="lg:col-span-3 space-y-4">
          <div className="rounded-2xl bg-white p-5 border border-gray-100 shadow-sm space-y-3">
            <div className="flex items-center justify-between flex-wrap gap-2">
              <h3 className="text-sm font-bold text-navy flex items-center gap-2">
                <Sparkles className="size-4 text-gold" /> {TEMPLATE_TYPES.find((t) => t.key === selectedKey)?.label}
              </h3>
              <div className="flex gap-2">
                <button onClick={() => setShowPreview(!showPreview)}
                  className="flex items-center gap-1 rounded-lg bg-gray-100 px-3 py-1.5 text-xs font-bold text-gray-700 hover:bg-gray-200">
                  <Eye className="size-3" /> {showPreview ? "إخفاء" : "معاينة"}
                </button>
                <button onClick={handleReset}
                  className="flex items-center gap-1 rounded-lg bg-amber-50 border border-amber-200 px-3 py-1.5 text-xs font-bold text-amber-700 hover:bg-amber-100">
                  <RefreshCw className="size-3" /> افتراضي
                </button>
              </div>
            </div>

            <div>
              <label className="text-xs font-bold text-gray-700 mb-1 block">📧 موضوع البريد</label>
              <input value={subject} onChange={(e) => setSubject(e.target.value)}
                className="w-full rounded-xl border border-gray-200 px-3 py-2.5 text-sm focus:border-gold focus:outline-none"
                placeholder="موضوع البريد" />
            </div>

            <div>
              <label className="text-xs font-bold text-gray-700 mb-1 block">💌 محتوى البريد (HTML)</label>
              <textarea value={bodyHtml} onChange={(e) => setBodyHtml(e.target.value)}
                className="w-full rounded-xl border border-gray-200 px-3 py-2.5 text-xs font-mono focus:border-gold focus:outline-none"
                rows={12} dir="ltr" />
            </div>

            {/* Variables */}
            <div className="rounded-xl bg-blue-50 p-3 border border-blue-200">
              <p className="text-xs font-bold text-blue-800 mb-2 flex items-center gap-1"><Info className="size-3" /> المتغيرات المتاحة (اضغط للإضافة):</p>
              <div className="flex flex-wrap gap-1.5">
                {AVAILABLE_VARS.map((v) => (
                  <button key={v.key} onClick={() => insertVariable(v.key)}
                    className="rounded-md bg-white border border-blue-200 px-2 py-1 text-[10px] font-mono text-blue-700 hover:bg-blue-100">
                    {v.key} <span className="text-gray-500">({v.desc})</span>
                  </button>
                ))}
              </div>
            </div>

            <button onClick={handleSave} disabled={saving}
              className="w-full flex items-center justify-center gap-2 rounded-xl bg-navy text-white py-3 text-sm font-bold hover:bg-navy-light shadow-lg disabled:opacity-50">
              {saving ? <Loader2 className="size-4 animate-spin" /> : <Save className="size-4" />}
              {saving ? "جاري الحفظ..." : "حفظ القالب"}
            </button>
          </div>

          {/* Preview */}
          {showPreview && (
            <div className="rounded-2xl bg-white p-5 border border-gray-100 shadow-sm">
              <h3 className="text-sm font-bold text-navy mb-3 flex items-center gap-2">
                <Eye className="size-4" /> معاينة مباشرة (ببيانات تجريبية)
              </h3>
              <div className="rounded-xl bg-gray-100 p-4">
                <div className="rounded-lg bg-white p-2 mb-3 shadow-sm">
                  <p className="text-[10px] text-gray-500">From: رداء &lt;noreply@rada.com&gt;</p>
                  <p className="text-[10px] text-gray-500">To: أحمد محمد &lt;ahmed@example.com&gt;</p>
                  <p className="text-sm font-bold text-navy mt-1">{subject
                    .replace(/{{name}}/g, "أحمد محمد")
                    .replace(/{{business_name}}/g, "رداء")
                    .replace(/{{order_number}}/g, "ORD-001")}</p>
                </div>
                <div className="rounded-lg bg-white p-3 shadow-sm" dangerouslySetInnerHTML={{ __html: previewHtml }} />
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState, useMemo } from "react";
import { Plus, Search, Filter, ChevronDown, Trash2, Receipt, TrendingDown, Megaphone, Truck as TruckIcon, Tag, Home, Users, Wrench, Package } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { useExpenseStore } from "@/stores/expenseStore";
import { formatCurrency, formatDate, getExpenseCategoryLabel, getExpenseCategoryColor } from "@/lib/formatters";
import StatCard from "@/components/features/StatCard";
import type { ExpenseCategory } from "@/types";

const EXPENSE_CATEGORIES: ExpenseCategory[] = ["advertising", "shipping", "promotions", "discounts", "rent", "salaries", "materials", "maintenance", "electricity", "commissions", "other"];

export default function Expenses() {
  const { user } = useAuth();
  const { expenses, initializeData, addExpense, deleteExpense, getTotalExpenses, getExpensesByCategory } = useExpenseStore();
  const [search, setSearch] = useState("");
  const [catFilter, setCatFilter] = useState<string>("all");
  const [showForm, setShowForm] = useState(false);
  const [fc, setFc] = useState<ExpenseCategory>("advertising");
  const [fd, setFd] = useState("");
  const [fa, setFa] = useState(0);
  const [fdate, setFdate] = useState("");
  const [fn, setFn] = useState("");

  useEffect(() => { if (user?.id) initializeData(user.id); }, [user?.id]);

  const totalExpenses = getTotalExpenses();
  const byCategory = getExpensesByCategory();

  const filtered = useMemo(() => {
    return expenses.filter((e) => {
      const matchSearch = !search || e.description.includes(search);
      const matchCat = catFilter === "all" || e.category === catFilter;
      return matchSearch && matchCat;
    }).sort((a, b) => b.date.localeCompare(a.date));
  }, [expenses, search, catFilter]);

  const handleAdd = async () => {
    if (!fd.trim()) { toast.error("يرجى إدخال وصف المصروف"); return; }
    if (fa <= 0) { toast.error("يرجى إدخال مبلغ صحيح"); return; }
    if (!user?.id) return;
    await addExpense({ category: fc, description: fd, amount: fa, date: fdate || new Date().toISOString().split("T")[0], notes: fn, isFixed: false }, user.id);
    toast.success("تم تسجيل المصروف");
    setShowForm(false); setFd(""); setFa(0); setFdate(""); setFn("");
  };

  const topCats = Object.entries(byCategory).sort((a, b) => b[1] - a[1]).slice(0, 3);

  return (
    <div className="space-y-4 lg:space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl">المصروفات</h1>
          <p className="text-xs text-gray-500 sm:text-sm">{expenses.length} مصروف مسجل</p>
        </div>
        <button onClick={() => setShowForm(true)} className="flex items-center justify-center gap-2 rounded-xl bg-navy px-5 py-3 text-sm font-bold text-white shadow-lg shadow-navy/20 hover:bg-navy-light active:scale-[0.98]">
          <Plus className="size-4" /> مصروف جديد
        </button>
      </div>

      <div className="grid grid-cols-2 gap-3 sm:grid-cols-2 xl:grid-cols-4 sm:gap-4">
        <StatCard title="إجمالي المصروفات" value={formatCurrency(totalExpenses)} icon={TrendingDown} delay={3} />
        {topCats.map(([cat, amount], idx) => (
          <StatCard key={cat} title={getExpenseCategoryLabel(cat)} value={formatCurrency(amount)} icon={Receipt} trend={`${((amount / totalExpenses) * 100).toFixed(0)}%`} delay={idx} />
        ))}
      </div>

      <div className="flex flex-col gap-2 rounded-2xl bg-white p-3 shadow-sm border border-gray-100 sm:flex-row sm:gap-3 sm:p-4">
        <div className="relative flex-1">
          <Search className="absolute right-3 top-1/2 size-4 -translate-y-1/2 text-gray-400" />
          <input type="text" value={search} onChange={(e) => setSearch(e.target.value)} className="w-full rounded-xl border border-gray-200 py-2.5 pe-4 ps-10 text-sm focus:border-gold focus:outline-none" placeholder="بحث في المصروفات..." />
        </div>
        <select value={catFilter} onChange={(e) => setCatFilter(e.target.value)} className="appearance-none rounded-xl border border-gray-200 bg-white py-2.5 px-3 text-sm focus:border-gold focus:outline-none">
          <option value="all">كل التصنيفات</option>
          {EXPENSE_CATEGORIES.map((c) => <option key={c} value={c}>{getExpenseCategoryLabel(c)}</option>)}
        </select>
      </div>

      <div className="rounded-2xl bg-white shadow-sm border border-gray-100 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full min-w-[600px]">
            <thead>
              <tr className="border-b bg-cream/50 text-right">
                <th className="px-4 py-3 text-xs font-semibold text-gray-500">التاريخ</th>
                <th className="px-4 py-3 text-xs font-semibold text-gray-500">التصنيف</th>
                <th className="px-4 py-3 text-xs font-semibold text-gray-500">الوصف</th>
                <th className="px-4 py-3 text-xs font-semibold text-gray-500">المبلغ</th>
                <th className="px-4 py-3 text-xs font-semibold text-gray-500">إجراء</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {filtered.map((expense, idx) => (
                <tr key={expense.id} className="hover:bg-cream/30 transition-colors animate-fade-in opacity-0" style={{ animationDelay: `${Math.min(idx, 15) * 30}ms` }}>
                  <td className="px-4 py-3 text-xs text-gray-500">{formatDate(expense.date)}</td>
                  <td className="px-4 py-3"><span className={`rounded-lg px-2 py-0.5 text-[10px] font-semibold ${getExpenseCategoryColor(expense.category)}`}>{getExpenseCategoryLabel(expense.category)}</span></td>
                  <td className="px-4 py-3 text-sm text-gray-700 max-w-[250px] truncate">{expense.description}</td>
                  <td className="px-4 py-3 text-sm font-bold text-red-600 tabular-nums">{formatCurrency(expense.amount)}</td>
                  <td className="px-4 py-3"><button onClick={() => { deleteExpense(expense.id); toast.success("تم حذف المصروف"); }} className="rounded-lg p-2 text-red-400 hover:bg-red-50"><Trash2 className="size-4" /></button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {filtered.length === 0 && <div className="py-16 text-center"><Receipt className="mx-auto size-12 text-gray-300" /><p className="mt-3 text-sm text-gray-400">لا توجد مصروفات</p></div>}
      </div>

      {showForm && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
