    ? { borderBottom: `4px double ${primary}`, paddingBottom: isThermal ? "0.5rem" : "1.5rem" }
    : { borderBottom: `1px solid ${primary}33`, paddingBottom: isThermal ? "0.4rem" : "1rem" };

