              <p className="text-center mt-2 pt-1" style={{ color: primary, borderTop: `1px dashed ${primary}`, fontSize: isCompact ? "8px" : "9px" }}>
                {settings.invoiceFooterText || `شكراً لتعاملكم مع ${businessName}`}
