import { useEffect, useState, useRef } from "react";
import { HardDrive, Download, Upload, Loader2, Info, Database, Shield, CheckCircle2, FileJson, Trash2, RefreshCw, Calendar } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { supabase } from "@/lib/supabase";
import { useAuditStore } from "@/stores/auditStore";
import { logActivity } from "@/hooks/useActivityLogger";

interface BackupMeta {
  version: string;
  createdAt: string;
  userId: string;
  userEmail: string;
  tables: Record<string, number>;
  totalRecords: number;
}

const BACKUP_TABLES = [
  "customers", "orders", "order_items", "payments", "products",
  "suppliers", "supplier_transactions", "sales_reps", "rep_commissions",
  "expenses", "returns", "return_items", "notifications",
  "audit_logs", "discount_rules", "partners_config", "user_roles",
  "email_templates", "app_settings", "rep_pricing", "report_schedules",
] as const;

export default function SmartBackups() {
  const { user } = useAuth();
  const { logAction } = useAuditStore();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [exporting, setExporting] = useState(false);
  const [importing, setImporting] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0, table: "" });
  const [stats, setStats] = useState<Record<string, number>>({});
  const [lastBackup, setLastBackup] = useState<string | null>(null);

  useEffect(() => {
    loadStats();
    const saved = localStorage.getItem("last_backup_date");
    if (saved) setLastBackup(saved);
  }, [user?.id]);

  const loadStats = async () => {
    if (!user?.id) return;
    const counts: Record<string, number> = {};
    for (const table of BACKUP_TABLES) {
      try {
        const { count } = await supabase.from(table).select("*", { count: "exact", head: true });
        counts[table] = count || 0;
      } catch {
        counts[table] = 0;
      }
    }
    setStats(counts);
  };

  const handleExport = async () => {
    if (!user?.id) return;
    setExporting(true);
    setProgress({ current: 0, total: BACKUP_TABLES.length, table: "" });

    const backup: { meta: BackupMeta; data: Record<string, unknown[]> } = {
      meta: {
        version: "1.0.0",
        createdAt: new Date().toISOString(),
        userId: user.id,
        userEmail: user.email,
        tables: {},
        totalRecords: 0,
      },
      data: {},
    };

    for (let i = 0; i < BACKUP_TABLES.length; i++) {
      const table = BACKUP_TABLES[i];
      setProgress({ current: i + 1, total: BACKUP_TABLES.length, table });
      try {
        const { data } = await supabase.from(table).select("*").limit(10000);
        backup.data[table] = data || [];
        backup.meta.tables[table] = (data || []).length;
        backup.meta.totalRecords += (data || []).length;
      } catch {
        backup.data[table] = [];
        backup.meta.tables[table] = 0;
      }
    }

    // Download as JSON
    const blob = new Blob([JSON.stringify(backup, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    const dateStr = new Date().toISOString().split("T")[0];
    a.href = url;
    a.download = `rada-backup-${dateStr}-${backup.meta.totalRecords}records.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    // Save last backup date
    const now = new Date().toISOString();
    localStorage.setItem("last_backup_date", now);
    setLastBackup(now);

    if (user?.id) {
      logAction(user.id, "export", "backup", undefined, `نسخة احتياطية شاملة: ${backup.meta.totalRecords} سجل من ${BACKUP_TABLES.length} جدول`);
      logActivity(user.email, user.id, "action", `نسخة احتياطية شاملة (${backup.meta.totalRecords} سجل)`, { entityType: "backup" });
    }

    toast.success(`✅ تم تصدير ${backup.meta.totalRecords} سجل`);
    setExporting(false);
    setProgress({ current: 0, total: 0, table: "" });
  };

  const handleImport = async (file: File) => {
    if (!user?.id) return;
    if (!confirm("⚠️ استعادة النسخة الاحتياطية قد تُنشئ سجلات مكررة. متابعة؟")) return;

    setImporting(true);
    try {
      const text = await file.text();
      const backup: { meta: BackupMeta; data: Record<string, unknown[]> } = JSON.parse(text);

      if (!backup.meta || !backup.data) {
        toast.error("ملف غير صالح - ليس نسخة احتياطية");
        setImporting(false);
        return;
      }

      let imported = 0;
      let failed = 0;
      const tableKeys = Object.keys(backup.data);
      setProgress({ current: 0, total: tableKeys.length, table: "" });

      for (let i = 0; i < tableKeys.length; i++) {
        const table = tableKeys[i];
        setProgress({ current: i + 1, total: tableKeys.length, table });
        const rows = backup.data[table] as Array<Record<string, unknown>>;
        if (rows.length === 0) continue;

        // Insert in batches of 100
        for (let j = 0; j < rows.length; j += 100) {
          const batch = rows.slice(j, j + 100);
          try {
            // Remove id and let DB regenerate to avoid conflicts
            const cleanBatch = batch.map((r) => {
              const { id, ...rest } = r;
              return rest;
            });
            const { error } = await supabase.from(table).insert(cleanBatch);
            if (error) failed += batch.length;
            else imported += batch.length;
          } catch {
            failed += batch.length;
          }
        }
      }

      if (user?.id) {
        logAction(user.id, "import", "backup", undefined, `استعادة نسخة احتياطية: ${imported} ناجح، ${failed} فشل`);
      }

      toast.success(`✅ تم استيراد ${imported} سجل${failed > 0 ? ` (فشل ${failed})` : ""}`);
      loadStats();
    } catch (err) {
      toast.error("فشل: " + (err instanceof Error ? err.message : "خطأ"));
    }
    setImporting(false);
    setProgress({ current: 0, total: 0, table: "" });
  };

  const totalRecords = Object.values(stats).reduce((s, c) => s + c, 0);

  return (
    <div className="space-y-4 lg:space-y-6">
      <div>
        <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl flex items-center gap-2">
          <HardDrive className="size-5 text-purple-600" /> النسخ الاحتياطي الذكي
        </h1>
        <p className="text-xs text-gray-500 sm:text-sm">حماية بياناتك بالتصدير والاستعادة الآمنة</p>
      </div>

      {/* Overview */}
      <div className="grid grid-cols-1 gap-3 sm:grid-cols-3">
        <div className="rounded-2xl bg-gradient-to-bl from-purple-500 to-purple-600 p-5 text-white shadow-lg shadow-purple-500/20">
          <Database className="size-6 mb-2" />
          <p className="text-xs text-white/80">إجمالي السجلات</p>
          <p className="text-3xl font-bold tabular-nums">{totalRecords.toLocaleString("ar-EG")}</p>
        </div>
        <div className="rounded-2xl bg-gradient-to-bl from-emerald-500 to-emerald-600 p-5 text-white shadow-lg shadow-emerald-500/20">
          <FileJson className="size-6 mb-2" />
          <p className="text-xs text-white/80">جداول محمية</p>
          <p className="text-3xl font-bold tabular-nums">{BACKUP_TABLES.length}</p>
        </div>
        <div className="rounded-2xl bg-gradient-to-bl from-blue-500 to-blue-600 p-5 text-white shadow-lg shadow-blue-500/20">
          <Calendar className="size-6 mb-2" />
          <p className="text-xs text-white/80">آخر نسخة</p>
          <p className="text-sm font-bold">
            {lastBackup ? new Date(lastBackup).toLocaleDateString("ar-SA") : "لا يوجد بعد"}
          </p>
          {lastBackup && (
            <p className="text-[10px] text-white/70 tabular-nums">
              {new Date(lastBackup).toLocaleTimeString("ar-SA", { hour: "2-digit", minute: "2-digit" })}
            </p>
          )}
        </div>
      </div>

      {/* Info */}
      <div className="rounded-2xl bg-blue-50 border-2 border-blue-200 p-5">
        <div className="flex items-start gap-3">
          <Info className="size-5 text-blue-600 shrink-0 mt-0.5" />
          <div className="text-sm text-blue-900">
            <p className="font-bold mb-1">💾 عن النسخ الاحتياطي:</p>
            <ul className="text-xs list-disc list-inside space-y-0.5">
              <li>يشمل: العملاء، الطلبات، المدفوعات، المنتجات، الموردين، المصروفات، المرتجعات، الإعدادات، الصلاحيات، والقواعد</li>
              <li>الملف يُحفظ محلياً على جهازك بصيغة JSON مقروءة</li>
              <li>يُنصح بأخذ نسخة أسبوعية على الأقل والاحتفاظ بها في مكان آمن</li>
              <li>الاستعادة ستُنشئ سجلات جديدة (لا تحذف الموجود) — احذر التكرار</li>
            </ul>
          </div>
        </div>
      </div>

      {/* Actions */}
      <div className="grid grid-cols-1 gap-4 lg:grid-cols-2">
        {/* Export */}
        <div className="rounded-2xl bg-white p-6 border-2 border-emerald-200 shadow-sm">
          <div className="flex items-start gap-3 mb-4">
            <div className="rounded-xl bg-emerald-100 p-3">
              <Download className="size-6 text-emerald-600" />
            </div>
            <div>
              <h3 className="text-base font-bold text-navy">📥 تصدير نسخة احتياطية</h3>
              <p className="text-xs text-gray-500 mt-1">قم بتنزيل نسخة كاملة من جميع بياناتك في ملف JSON</p>
            </div>
          </div>
          {exporting && progress.total > 0 && (
            <div className="mb-3">
              <div className="flex items-center justify-between text-xs mb-1">
                <span className="text-gray-600">جاري النسخ: {progress.table}</span>
                <span className="font-bold text-emerald-600">{progress.current}/{progress.total}</span>
              </div>
              <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
                <div className="h-full bg-emerald-500 transition-all" style={{ width: `${(progress.current / progress.total) * 100}%` }} />
              </div>
            </div>
          )}
          <button onClick={handleExport} disabled={exporting || importing}
            className="w-full flex items-center justify-center gap-2 rounded-xl bg-emerald-500 text-white py-3 text-sm font-bold hover:bg-emerald-600 shadow-md disabled:opacity-50">
            {exporting ? <Loader2 className="size-4 animate-spin" /> : <Download className="size-4" />}
            {exporting ? "جاري التصدير..." : "بدء النسخ الاحتياطي الآن"}
          </button>
        </div>

        {/* Import */}
        <div className="rounded-2xl bg-white p-6 border-2 border-amber-200 shadow-sm">
          <div className="flex items-start gap-3 mb-4">
            <div className="rounded-xl bg-amber-100 p-3">
              <Upload className="size-6 text-amber-600" />
            </div>
            <div>
              <h3 className="text-base font-bold text-navy">📤 استعادة نسخة احتياطية</h3>
              <p className="text-xs text-gray-500 mt-1">استعد بياناتك من ملف JSON محفوظ سابقاً</p>
            </div>
          </div>
          {importing && progress.total > 0 && (
            <div className="mb-3">
              <div className="flex items-center justify-between text-xs mb-1">
                <span className="text-gray-600">جاري الاستيراد: {progress.table}</span>
                <span className="font-bold text-amber-600">{progress.current}/{progress.total}</span>
              </div>
              <div className="h-2 bg-gray-100 rounded-full overflow-hidden">
                <div className="h-full bg-amber-500 transition-all" style={{ width: `${(progress.current / progress.total) * 100}%` }} />
              </div>
            </div>
          )}
          <input ref={fileInputRef} type="file" accept=".json" className="hidden"
            onChange={(e) => { const f = e.target.files?.[0]; if (f) handleImport(f); e.target.value = ""; }} />
          <button onClick={() => fileInputRef.current?.click()} disabled={exporting || importing}
            className="w-full flex items-center justify-center gap-2 rounded-xl bg-amber-500 text-white py-3 text-sm font-bold hover:bg-amber-600 shadow-md disabled:opacity-50">
            {importing ? <Loader2 className="size-4 animate-spin" /> : <Upload className="size-4" />}
            {importing ? "جاري الاستيراد..." : "اختر ملف JSON للاستعادة"}
          </button>
        </div>
      </div>

      {/* Stats table */}
      <div className="rounded-2xl bg-white p-5 border border-gray-100 shadow-sm">
        <div className="flex items-center justify-between mb-4">
          <h3 className="text-sm font-bold text-navy flex items-center gap-2">
            <Database className="size-4" /> إحصاء البيانات الحالية
          </h3>
          <button onClick={loadStats} className="flex items-center gap-1 rounded-lg bg-gray-100 px-3 py-1.5 text-xs font-bold hover:bg-gray-200">
            <RefreshCw className="size-3" /> تحديث
          </button>
        </div>
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-2">
          {BACKUP_TABLES.map((table) => (
            <div key={table} className="flex items-center justify-between rounded-lg bg-cream/40 p-2.5 border border-gray-100">
              <span className="text-[11px] text-gray-600 font-semibold truncate" dir="ltr">{table}</span>
              <span className="text-xs font-bold text-navy tabular-nums bg-white px-2 rounded">
                {(stats[table] || 0).toLocaleString("ar-EG")}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Best practices */}
      <div className="rounded-2xl bg-emerald-50 border border-emerald-200 p-4">
        <div className="flex items-start gap-3">
          <Shield className="size-5 text-emerald-600 shrink-0 mt-0.5" />
          <div className="text-sm text-emerald-900">
            <p className="font-bold mb-2">🛡️ أفضل الممارسات:</p>
            <ul className="text-xs list-disc list-inside space-y-0.5">
              <li>خذ نسخة أسبوعياً كل يوم أحد</li>
              <li>خزّن النسخ في مكانين على الأقل (جهازك + Google Drive/Dropbox)</li>
              <li>احتفظ بآخر 4 نسخ على الأقل قبل حذف القديم</li>
              <li>قبل أي تحديث كبير أو عملية جماعية، خذ نسخة احتياطية</li>
              <li>اختبر الاستعادة سنوياً للتأكد من سلامة النسخ</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState, useMemo } from "react";
import { Plus, Search, Truck, ChevronDown, ChevronUp, DollarSign, Package, Trash2, Ruler } from "lucide-react";
import { toast } from "sonner";
import { useAuth } from "@/hooks/useAuth";
import { useSupplierStore } from "@/stores/supplierStore";
import { formatCurrency, formatDual, formatDate, getTxTypeLabel, getTxTypeColor } from "@/lib/formatters";
import StatCard from "@/components/features/StatCard";
import { CITIES, FABRIC_UNITS } from "@/constants/config";

export default function Suppliers() {
  const { user } = useAuth();
  const { suppliers, transactions, initializeData, addSupplier, deleteSupplier, addTransaction, deleteTransaction, getSupplierBalance, getTotalSupplierDebt, getTotalFabricByUnit } = useSupplierStore();
  const [search, setSearch] = useState("");
  const [expandedId, setExpandedId] = useState<string | null>(null);
  const [showAddSupplier, setShowAddSupplier] = useState(false);
  const [showAddTx, setShowAddTx] = useState<string | null>(null);
  const [sf, setSf] = useState({ name: "", phone: "", email: "", company: "", city: "", notes: "" });
  const [tf, setTf] = useState({ type: "purchase" as "purchase" | "payment" | "return", amount: 0, pieces: 0, fabricType: "", fabricUnit: "متر", fabricQuantity: 0, date: "", notes: "" });

  useEffect(() => { if (user?.id) initializeData(user.id); }, [user?.id]);

  const totalDebt = getTotalSupplierDebt();
  const totalFabric = getTotalFabricByUnit();
  const filtered = useMemo(() => suppliers.filter((s) => s.name.includes(search) || s.company.includes(search) || s.phone.includes(search)), [suppliers, search]);

  const handleAddSupplier = async () => {
    if (!sf.name.trim()) { toast.error("يرجى إدخال اسم المورد"); return; }
    if (!user?.id) return;
    await addSupplier(sf, user.id);
    toast.success("تم إضافة المورد");
    setSf({ name: "", phone: "", email: "", company: "", city: "", notes: "" });
    setShowAddSupplier(false);
  };

  const handleAddTx = async (supplierId: string, supplierName: string) => {
    if (tf.amount <= 0 && tf.type !== "purchase") { toast.error("يرجى إدخال مبلغ صحيح"); return; }
    if (tf.type === "purchase" && tf.amount <= 0 && tf.fabricQuantity <= 0) { toast.error("يرجى إدخال مبلغ أو كمية"); return; }
    await addTransaction({ supplierId, supplierName, ...tf, date: tf.date || new Date().toISOString().split("T")[0] });
    toast.success("تم تسجيل العملية");
    setTf({ type: "purchase", amount: 0, pieces: 0, fabricType: "", fabricUnit: "متر", fabricQuantity: 0, date: "", notes: "" });
    setShowAddTx(null);
  };

  return (
    <div className="space-y-4 lg:space-y-6">
      <div className="flex flex-col gap-3 sm:flex-row sm:items-center sm:justify-between">
        <div>
          <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl">الموردون والتجار</h1>
          <p className="text-xs text-gray-500 sm:text-sm">{suppliers.length} مورد مسجل</p>
        </div>
        <button onClick={() => setShowAddSupplier(true)}
          className="flex items-center justify-center gap-2 rounded-xl bg-navy px-5 py-3 text-sm font-bold text-white shadow-lg shadow-navy/20 hover:bg-navy-light active:scale-[0.98]">
          <Plus className="size-4" /> مورد جديد
        </button>
      </div>

      <div className="grid grid-cols-1 gap-3 sm:grid-cols-2 lg:grid-cols-4 sm:gap-4">
        <StatCard title="إجمالي المستحق" value={formatCurrency(totalDebt)} icon={DollarSign} delay={3} />
        <StatCard title="عدد الموردين" value={`${suppliers.length} مورد`} icon={Truck} delay={0} />
        <StatCard title="إجمالي المعاملات" value={`${transactions.length} عملية`} icon={Package} delay={1} />
        <div className="rounded-2xl bg-white p-4 shadow-sm border border-gray-100">
          <div className="flex items-center gap-2 mb-2">
            <div className="rounded-lg bg-cyan-50 p-2"><Ruler className="size-4 text-cyan-600" /></div>
            <span className="text-xs font-semibold text-gray-500">الأقمشة المتبقية</span>
          </div>
          <div className="space-y-1">
            {Object.entries(totalFabric).length > 0 ? Object.entries(totalFabric).map(([unit, qty]) => (
              <p key={unit} className="text-sm font-bold text-navy">{qty.toLocaleString("ar-YE")} <span className="text-xs font-normal text-gray-400">{unit}</span></p>
            )) : <p className="text-xs text-gray-400">لا توجد بيانات</p>}
          </div>
        </div>
      </div>

      <div className="relative max-w-md">
        <Search className="absolute right-3 top-1/2 size-4 -translate-y-1/2 text-gray-400" />
        <input type="text" value={search} onChange={(e) => setSearch(e.target.value)}
          className="w-full rounded-xl border border-gray-200 bg-white py-2.5 pe-4 ps-10 text-sm shadow-sm focus:border-gold focus:outline-none" placeholder="بحث بالاسم أو الشركة..." />
      </div>

      <div className="space-y-3">
        {filtered.map((supplier, idx) => {
          const balance = getSupplierBalance(supplier.id);
          const isExpanded = expandedId === supplier.id;
          const supplierTxs = transactions.filter((t) => t.supplierId === supplier.id).sort((a, b) => b.date.localeCompare(a.date));
          return (
            <div key={supplier.id} className="rounded-2xl bg-white shadow-sm border border-gray-100 overflow-hidden animate-fade-in opacity-0" style={{ animationDelay: `${idx * 50}ms` }}>
              <div className="flex flex-col gap-3 p-4 cursor-pointer hover:bg-cream/30 transition-colors sm:flex-row sm:items-center sm:justify-between sm:p-5" onClick={() => setExpandedId(isExpanded ? null : supplier.id)}>
                <div className="flex items-center gap-3">
                  <div className="flex size-10 items-center justify-center rounded-full bg-gradient-to-bl from-navy to-navy-light text-xs font-bold text-white sm:size-12 sm:text-sm">{supplier.name.charAt(0)}</div>
                  <div>
                    <h3 className="text-sm font-bold text-navy">{supplier.name}</h3>
                    <p className="text-[10px] text-gray-400 sm:text-xs">{supplier.company} · {supplier.city}</p>
                  </div>
                </div>
                <div className="flex items-center justify-between sm:gap-4">
                  <div className="grid grid-cols-3 gap-3 text-center sm:gap-4">
                    <div><p className="text-[10px] text-gray-400">المشتريات</p><p className="text-xs font-bold text-red-600 tabular-nums">{formatCurrency(balance.totalPurchases)}</p></div>
                    <div><p className="text-[10px] text-gray-400">المدفوع</p><p className="text-xs font-bold text-green-600 tabular-nums">{formatCurrency(balance.totalPayments)}</p></div>
                    <div><p className="text-[10px] text-gray-400">المتبقي</p><p className={`text-sm font-bold tabular-nums ${balance.remaining > 0 ? "text-red-600" : "text-green-600"}`}>{formatCurrency(Math.max(0, balance.remaining))}</p></div>
                  </div>
                  {/* Fabric summary */}
                  {Object.entries(balance.fabricByUnit).length > 0 && (
                    <div className="hidden sm:flex items-center gap-2 rounded-lg bg-cyan-50 px-3 py-1.5">
                      <Ruler className="size-3.5 text-cyan-600" />
                      {Object.entries(balance.fabricByUnit).map(([unit, qty]) => (
                        <span key={unit} className="text-xs font-bold text-cyan-700">{qty} {unit}</span>
                      ))}
                    </div>
                  )}
                  {isExpanded ? <ChevronUp className="size-5 text-gray-400 hidden sm:block" /> : <ChevronDown className="size-5 text-gray-400 hidden sm:block" />}
                </div>
              </div>
              {isExpanded && (
                <div className="border-t bg-cream/20 p-4 space-y-3 sm:p-5">
                  <div className="flex items-center justify-between">
                    <h4 className="text-sm font-bold text-navy">سجل العمليات</h4>
                    <button onClick={(e) => { e.stopPropagation(); setShowAddTx(supplier.id); }}
                      className="flex items-center gap-1.5 rounded-lg bg-navy px-3 py-2 text-xs font-semibold text-white hover:bg-navy-light">
                      <Plus className="size-3.5" /> عملية جديدة
                    </button>
                  </div>
                  {showAddTx === supplier.id && (
                    <div className="rounded-xl bg-white border border-gray-200 p-4 space-y-3">
                      <div className="grid grid-cols-3 gap-2">
                        {(["purchase", "payment", "return"] as const).map((t) => (
                          <button key={t} onClick={() => setTf({ ...tf, type: t })}
                            className={`rounded-lg py-2 text-xs font-semibold ${tf.type === t ? "bg-navy text-white" : "bg-gray-100 text-gray-600 hover:bg-gray-200"}`}>
                            {getTxTypeLabel(t)}
                          </button>
                        ))}
                      </div>
                      <div className="grid grid-cols-2 gap-3">
                        <div><label className="mb-1 block text-xs font-semibold text-gray-600">المبلغ</label>
                          <input type="number" min="0" value={tf.amount || ""} onChange={(e) => setTf({ ...tf, amount: parseFloat(e.target.value) || 0 })} className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none" /></div>
                        <div><label className="mb-1 block text-xs font-semibold text-gray-600">عدد القطع</label>
                          <input type="number" min="0" value={tf.pieces || ""} onChange={(e) => setTf({ ...tf, pieces: parseInt(e.target.value) || 0 })} className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none" /></div>
                        <div><label className="mb-1 block text-xs font-semibold text-gray-600">نوع القماش</label>
                          <input value={tf.fabricType} onChange={(e) => setTf({ ...tf, fabricType: e.target.value })} className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none" /></div>
                        <div><label className="mb-1 block text-xs font-semibold text-gray-600">التاريخ</label>
                          <input type="date" value={tf.date} onChange={(e) => setTf({ ...tf, date: e.target.value })} className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none" /></div>
                        <div><label className="mb-1 block text-xs font-semibold text-gray-600">كمية القماش</label>
                          <input type="number" min="0" step="0.5" value={tf.fabricQuantity || ""} onChange={(e) => setTf({ ...tf, fabricQuantity: parseFloat(e.target.value) || 0 })} className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none" /></div>
                        <div><label className="mb-1 block text-xs font-semibold text-gray-600">وحدة القياس</label>
                          <select value={tf.fabricUnit} onChange={(e) => setTf({ ...tf, fabricUnit: e.target.value })} className="w-full rounded-lg border border-gray-200 bg-white px-3 py-2 text-sm focus:border-gold focus:outline-none">
                            {FABRIC_UNITS.map((u) => <option key={u.value} value={u.value}>{u.label}</option>)}
                          </select></div>
                      </div>
                      <div><label className="mb-1 block text-xs font-semibold text-gray-600">ملاحظات</label>
                        <input value={tf.notes} onChange={(e) => setTf({ ...tf, notes: e.target.value })} className="w-full rounded-lg border border-gray-200 px-3 py-2 text-sm focus:border-gold focus:outline-none" /></div>
                      <div className="flex gap-2">
                        <button onClick={() => handleAddTx(supplier.id, supplier.name)} className="flex-1 rounded-lg bg-emerald-600 py-2 text-xs font-bold text-white hover:bg-emerald-700">حفظ</button>
                        <button onClick={() => setShowAddTx(null)} className="rounded-lg border border-gray-200 px-4 py-2 text-xs font-semibold text-gray-600">إلغاء</button>
                      </div>
                    </div>
                  )}
                  {supplierTxs.map((tx) => (
                    <div key={tx.id} className="flex items-center justify-between rounded-xl bg-white p-3 border border-gray-100 sm:p-4">
                      <div className="flex items-center gap-3">
                        <span className={`rounded-lg px-2.5 py-1 text-xs font-bold ${getTxTypeColor(tx.type)}`}>{getTxTypeLabel(tx.type)}</span>
                        <div>
                          <p className="text-sm font-semibold text-navy">{formatCurrency(tx.amount)}</p>
                          <p className="text-xs text-gray-400">
                            {formatDate(tx.date)}
                            {tx.pieces > 0 && ` · ${tx.pieces} قطعة`}
                            {tx.fabricQuantity > 0 && ` · ${tx.fabricQuantity} ${tx.fabricUnit}`}
                            {tx.fabricType && ` (${tx.fabricType})`}
                          </p>
                        </div>
                      </div>
                      <button onClick={() => { deleteTransaction(tx.id); toast.success("تم حذف العملية"); }} className="rounded-lg p-2 text-red-400 hover:bg-red-50"><Trash2 className="size-4" /></button>
                    </div>
                  ))}
                  {supplierTxs.length === 0 && <p className="text-center text-xs text-gray-400 py-4">لا توجد عمليات مسجلة</p>}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {showAddSupplier && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4">
          <div className="w-full max-w-lg animate-scale-in rounded-2xl bg-white shadow-2xl">
            <div className="flex items-center justify-between border-b px-6 py-4">
              <h2 className="text-lg font-bold text-navy">مورد جديد</h2>
              <button onClick={() => setShowAddSupplier(false)} className="rounded-lg p-2 hover:bg-gray-100">✕</button>
            </div>
            <div className="space-y-4 p-6">
              <div className="grid grid-cols-2 gap-4">
                <div><label className="mb-1.5 block text-sm font-semibold text-gray-700">اسم المورد</label>
                  <input value={sf.name} onChange={(e) => setSf({ ...sf, name: e.target.value })} className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none" /></div>
                <div><label className="mb-1.5 block text-sm font-semibold text-gray-700">الشركة</label>
                  <input value={sf.company} onChange={(e) => setSf({ ...sf, company: e.target.value })} className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none" /></div>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div><label className="mb-1.5 block text-sm font-semibold text-gray-700">الهاتف</label>
                  <input value={sf.phone} onChange={(e) => setSf({ ...sf, phone: e.target.value })} dir="ltr" className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none" /></div>
                <div><label className="mb-1.5 block text-sm font-semibold text-gray-700">المدينة</label>
                  <select value={sf.city} onChange={(e) => setSf({ ...sf, city: e.target.value })} className="w-full rounded-xl border border-gray-200 bg-white px-4 py-2.5 text-sm focus:border-gold focus:outline-none">
                    <option value="">اختر المدينة</option>
                    {CITIES.map((c) => <option key={c} value={c}>{c}</option>)}
                  </select></div>
              </div>
              <div><label className="mb-1.5 block text-sm font-semibold text-gray-700">ملاحظات</label>
                <textarea value={sf.notes} onChange={(e) => setSf({ ...sf, notes: e.target.value })} rows={2} className="w-full rounded-xl border border-gray-200 px-4 py-2.5 text-sm focus:border-gold focus:outline-none resize-none" /></div>
            </div>
            <div className="flex gap-3 border-t bg-gray-50 px-6 py-4 rounded-b-2xl">
              <button onClick={handleAddSupplier} className="flex-1 rounded-xl bg-navy py-3 text-sm font-bold text-white hover:bg-navy-light active:scale-[0.98]">حفظ المورد</button>
              <button onClick={() => setShowAddSupplier(false)} className="rounded-xl border border-gray-200 bg-white px-6 py-3 text-sm font-semibold text-gray-600 hover:bg-gray-50">إلغاء</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useEffect, useMemo, useState } from "react";
import { Link, useParams } from "react-router-dom";
import { ArrowLeft, User, Clock, MapPin, Activity, LogIn, LogOut, MousePointerClick, FileText, Loader2, Calendar, Filter, RefreshCw } from "lucide-react";
import { supabase } from "@/lib/supabase";
import { formatDate } from "@/lib/formatters";

interface ActivityRow {
  id: string;
  user_email: string;
  user_id: string | null;
  action_type: string;
  action_name: string;
  page_path: string;
  entity_type: string;
  entity_id: string;
  details: string;
  ip_address: string;
  user_agent: string;
  created_at: string;
}

const TYPE_ICONS: Record<string, typeof Activity> = {
  login: LogIn,
  logout: LogOut,
  page_visit: MousePointerClick,
  action: FileText,
};

const TYPE_COLORS: Record<string, { bg: string; text: string; ring: string }> = {
  login: { bg: "bg-emerald-500", text: "text-emerald-700", ring: "ring-emerald-200" },
  logout: { bg: "bg-gray-500", text: "text-gray-700", ring: "ring-gray-200" },
  page_visit: { bg: "bg-blue-500", text: "text-blue-700", ring: "ring-blue-200" },
  action: { bg: "bg-purple-500", text: "text-purple-700", ring: "ring-purple-200" },
};

const TYPE_LABELS: Record<string, string> = {
  login: "تسجيل دخول",
  logout: "تسجيل خروج",
  page_visit: "زيارة صفحة",
  action: "إجراء",
};

export default function UserActivity() {
  const { email } = useParams<{ email: string }>();
  const decodedEmail = email ? decodeURIComponent(email) : "";
  const [logs, setLogs] = useState<ActivityRow[]>([]);
  const [loading, setLoading] = useState(true);
  const [typeFilter, setTypeFilter] = useState<string>("all");
  const [daysFilter, setDaysFilter] = useState<number>(30);

  const loadLogs = async () => {
    if (!decodedEmail) return;
    setLoading(true);
    const cutoff = new Date(Date.now() - daysFilter * 86400000).toISOString();
    const { data, error } = await supabase
      .from("user_activity_logs")
      .select("*")
      .eq("user_email", decodedEmail)
      .gte("created_at", cutoff)
      .order("created_at", { ascending: false })
      .limit(500);

    if (error) {
      console.error("Failed to load activity:", error);
    } else {
      setLogs((data || []) as ActivityRow[]);
    }
    setLoading(false);
  };

  useEffect(() => { loadLogs(); }, [decodedEmail, daysFilter]);

  const filtered = useMemo(() => {
    if (typeFilter === "all") return logs;
    return logs.filter((l) => l.action_type === typeFilter);
  }, [logs, typeFilter]);

  const stats = useMemo(() => {
    const total = logs.length;
    const logins = logs.filter((l) => l.action_type === "login").length;
    const pageVisits = logs.filter((l) => l.action_type === "page_visit").length;
    const actions = logs.filter((l) => l.action_type === "action").length;
    const lastLogin = logs.find((l) => l.action_type === "login")?.created_at;
    const lastActivity = logs[0]?.created_at;
    const uniquePages = new Set(logs.filter((l) => l.page_path).map((l) => l.page_path)).size;
    return { total, logins, pageVisits, actions, lastLogin, lastActivity, uniquePages };
  }, [logs]);

  // Group by date for timeline
  const groupedByDate = useMemo(() => {
    const groups: Record<string, ActivityRow[]> = {};
    filtered.forEach((log) => {
      const date = new Date(log.created_at).toLocaleDateString("ar-SA", { year: "numeric", month: "long", day: "numeric" });
      if (!groups[date]) groups[date] = [];
      groups[date].push(log);
    });
    return Object.entries(groups);
  }, [filtered]);

  return (
    <div className="space-y-4 lg:space-y-6">
      <div>
        <Link to="/roles" className="flex items-center gap-2 text-sm font-semibold text-gray-500 hover:text-navy mb-2">
          <ArrowLeft className="size-4" /> العودة لإدارة الصلاحيات
        </Link>
        <div className="flex items-center gap-3 flex-wrap">
          <div className="flex size-14 items-center justify-center rounded-full bg-gradient-to-bl from-navy to-navy-light text-white font-bold text-xl shrink-0">
            {decodedEmail.charAt(0).toUpperCase()}
          </div>
          <div className="flex-1 min-w-0">
            <h1 className="text-lg font-bold text-navy sm:text-xl lg:text-2xl flex items-center gap-2">
              <Activity className="size-5 text-gold" /> سجل نشاط المستخدم
            </h1>
            <p className="text-xs text-gray-500 sm:text-sm" dir="ltr">{decodedEmail}</p>
          </div>
          <button onClick={loadLogs}
            className="flex items-center gap-2 rounded-xl bg-white border border-gray-200 px-4 py-2.5 text-xs font-bold text-navy hover:bg-cream/50">
            <RefreshCw className="size-3.5" /> تحديث
          </button>
        </div>
      </div>

      {/* Stats grid */}
      <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
        <div className="rounded-2xl bg-gradient-to-bl from-emerald-500 to-emerald-600 p-4 text-white shadow-lg shadow-emerald-500/20">
          <LogIn className="size-5 mb-2" />
          <p className="text-xs text-white/80">مرات الدخول</p>
          <p className="text-2xl font-bold tabular-nums">{stats.logins}</p>
          {stats.lastLogin && (
            <p className="text-[10px] text-white/70 mt-1">آخر: {formatDate(stats.lastLogin)}</p>
          )}
        </div>
        <div className="rounded-2xl bg-gradient-to-bl from-blue-500 to-blue-600 p-4 text-white shadow-lg shadow-blue-500/20">
          <MousePointerClick className="size-5 mb-2" />
          <p className="text-xs text-white/80">زيارات صفحات</p>
          <p className="text-2xl font-bold tabular-nums">{stats.pageVisits}</p>
          <p className="text-[10px] text-white/70 mt-1">{stats.uniquePages} صفحة فريدة</p>
        </div>
        <div className="rounded-2xl bg-gradient-to-bl from-purple-500 to-purple-600 p-4 text-white shadow-lg shadow-purple-500/20">
          <FileText className="size-5 mb-2" />
          <p className="text-xs text-white/80">إجراءات</p>
          <p className="text-2xl font-bold tabular-nums">{stats.actions}</p>
          <p className="text-[10px] text-white/70 mt-1">مسجّل: {stats.total}</p>
        </div>
        <div className="rounded-2xl bg-white p-4 border border-gray-100 shadow-sm">
          <Clock className="size-5 text-gold-dark mb-2" />
          <p className="text-xs text-gray-500">آخر نشاط</p>
          {stats.lastActivity ? (
            <>
              <p className="text-sm font-bold text-navy">{formatDate(stats.lastActivity)}</p>
              <p className="text-[10px] text-gray-400 mt-1">
                {(() => {
                  const diff = Date.now() - new Date(stats.lastActivity).getTime();
                  const days = Math.floor(diff / 86400000);
                  const hours = Math.floor((diff % 86400000) / 3600000);
                  if (days === 0 && hours === 0) return "قبل دقائق";
                  if (days === 0) return `قبل ${hours} ساعة`;
                  return `قبل ${days} يوم`;
                })()}
              </p>
            </>
          ) : (
            <p className="text-sm text-gray-400">لا يوجد</p>
          )}
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-col gap-3 rounded-2xl bg-white p-4 border border-gray-100 shadow-sm sm:flex-row">
        <div className="flex items-center gap-2 flex-1 flex-wrap">
          <Filter className="size-4 text-gray-400" />
          <span className="text-[11px] text-gray-500 shrink-0">نوع النشاط:</span>
          <div className="flex gap-1.5 flex-wrap">
            <button onClick={() => setTypeFilter("all")}
              className={`rounded-lg px-3 py-1 text-[11px] font-semibold transition-colors ${
                typeFilter === "all" ? "bg-navy text-white" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
              }`}>
              الكل ({logs.length})
            </button>
            {Object.entries(TYPE_LABELS).map(([type, label]) => (
              <button key={type} onClick={() => setTypeFilter(type)}
                className={`rounded-lg px-3 py-1 text-[11px] font-semibold transition-colors ${
                  typeFilter === type ? "bg-navy text-white" : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                }`}>
                {label} ({logs.filter((l) => l.action_type === type).length})
              </button>
            ))}
          </div>
        </div>
        <div className="flex items-center gap-2">
          <Calendar className="size-4 text-gray-400" />
          <select value={daysFilter} onChange={(e) => setDaysFilter(parseInt(e.target.value))}
            className="rounded-lg border border-gray-200 bg-white px-3 py-1.5 text-xs focus:border-gold focus:outline-none">
            <option value={1}>آخر يوم</option>
            <option value={7}>آخر 7 أيام</option>
            <option value={30}>آخر 30 يوم</option>
            <option value={90}>آخر 90 يوم</option>
            <option value={365}>آخر سنة</option>
          </select>
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-20">
          <Loader2 className="size-8 animate-spin text-navy" />
        </div>
      ) : filtered.length === 0 ? (
        <div className="flex flex-col items-center gap-4 py-16 rounded-2xl bg-white border border-gray-100">
          <div className="rounded-full bg-gray-100 p-6"><Activity className="size-10 text-gray-300" /></div>
          <h3 className="text-lg font-bold text-navy">لا يوجد نشاط</h3>
          <p className="text-sm text-gray-400">لم يقم المستخدم بأي نشاط في هذه الفترة</p>
        </div>
      ) : (
        <div className="space-y-6">
          {groupedByDate.map(([date, entries]) => (
            <div key={date}>
              <div className="sticky top-0 z-10 bg-cream/95 backdrop-blur-sm py-2 mb-3 rounded-lg px-3 border border-gold/20">
                <p className="text-xs font-bold text-navy flex items-center gap-2">
                  <Calendar className="size-3.5" /> {date} <span className="text-gray-400 font-normal">— {entries.length} نشاط</span>
                </p>
              </div>
              <div className="relative">
                <div className="absolute right-[19px] top-2 bottom-2 w-0.5 bg-gray-200" />
                <div className="space-y-2">
                  {entries.map((log, idx) => {
                    const Icon = TYPE_ICONS[log.action_type] || Activity;
                    const colors = TYPE_COLORS[log.action_type] || TYPE_COLORS.action;
                    return (
                      <div key={log.id} className="relative flex gap-3 animate-fade-in opacity-0"
                        style={{ animationDelay: `${Math.min(idx, 20) * 30}ms` }}>
                        <div className={`relative z-10 flex size-10 shrink-0 items-center justify-center rounded-full ${colors.bg} text-white ring-4 ring-white shadow-md`}>
                          <Icon className="size-4" />
                        </div>
                        <div className={`flex-1 rounded-xl bg-white p-3 ring-1 ${colors.ring} border border-gray-100`}>
                          <div className="flex items-start justify-between gap-2 flex-wrap">
                            <div className="flex-1 min-w-0">
                              <div className="flex items-center gap-2 flex-wrap">
                                <span className={`text-xs font-bold ${colors.text}`}>{log.action_name || TYPE_LABELS[log.action_type]}</span>
                                <span className={`rounded-md bg-cream/60 px-1.5 py-0.5 text-[9px] font-semibold text-gray-500`}>
                                  {TYPE_LABELS[log.action_type] || log.action_type}
                                </span>
                              </div>
                              {log.details && <p className="text-[11px] text-gray-500 mt-1">{log.details}</p>}
                              {log.page_path && log.action_type === "page_visit" && (
                                <p className="text-[10px] text-gray-400 mt-1" dir="ltr">{log.page_path}</p>
                              )}
                              {log.user_agent && (
                                <p className="text-[9px] text-gray-300 mt-1 line-clamp-1" title={log.user_agent}>
                                  {log.user_agent.substring(0, 60)}
                                </p>
                              )}
                            </div>
                            <span className="text-[10px] text-gray-400 shrink-0 tabular-nums">
                              {new Date(log.created_at).toLocaleTimeString("ar-SA", { hour: "2-digit", minute: "2-digit" })}
                            </span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

import { create } from "zustand";
import { supabase } from "@/lib/supabase";

export interface AuditLog {
  id: string;
  action: string;
  entityType: string;
  entityId?: string;
  details: string;
  createdAt: string;
  ipAddress?: string;
  userAgent?: string;
  deviceInfo?: string;
}

function getDeviceInfo(): string {
  if (typeof navigator === "undefined") return "";
  const ua = navigator.userAgent;
  const isMobile = /Mobile|Android|iPhone|iPad/i.test(ua);
  const browser = /Chrome/.test(ua) ? "Chrome" : /Firefox/.test(ua) ? "Firefox" : /Safari/.test(ua) ? "Safari" : /Edge/.test(ua) ? "Edge" : "غير معروف";
  const os = /Windows/.test(ua) ? "Windows" : /Mac/.test(ua) ? "macOS" : /Linux/.test(ua) ? "Linux" : /Android/.test(ua) ? "Android" : /iOS|iPhone|iPad/.test(ua) ? "iOS" : "غير معروف";
  return `${browser} · ${os} · ${isMobile ? "جوال" : "سطح مكتب"}`;
}

interface AuditState {
  logs: AuditLog[];
  loading: boolean;
  initialized: boolean;
  initializeLogs: (userId: string) => Promise<void>;
  logAction: (userId: string, action: string, entityType: string, entityId: string | undefined, details: string) => Promise<void>;
}

export const useAuditStore = create<AuditState>()((set, get) => ({
  logs: [],
  loading: true,
  initialized: false,

  initializeLogs: async (userId: string) => {
    if (get().initialized) return;
    const { data } = await supabase.from("audit_logs").select("*").eq("user_id", userId).order("created_at", { ascending: false }).limit(200);
    const logs = (data || []).map((r: any) => ({
      id: r.id, action: r.action, entityType: r.entity_type,
      entityId: r.entity_id, details: r.details, createdAt: r.created_at,
      ipAddress: r.ip_address || "", userAgent: r.user_agent || "", deviceInfo: r.device_info || "",
    }));
    set({ logs, loading: false, initialized: true });
  },

  logAction: async (userId, action, entityType, entityId, details) => {
    const deviceInfo = getDeviceInfo();
    const userAgent = typeof navigator !== "undefined" ? navigator.userAgent.substring(0, 200) : "";
    const { data: row } = await supabase.from("audit_logs").insert({
      user_id: userId, action, entity_type: entityType, entity_id: entityId || "", details,
      device_info: deviceInfo, user_agent: userAgent, ip_address: "",
    }).select().single();
    if (row) {
      const newLog: AuditLog = { id: row.id, action, entityType, entityId, details, createdAt: row.created_at, deviceInfo, userAgent };
      set((s) => ({ logs: [newLog, ...s.logs].slice(0, 200) }));
    }
  },
}));

import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import type { Customer, Order, OrderItem, Payment } from "@/types";
import { generateOrderNumber } from "@/lib/utils";
import { toast } from "sonner";

interface DataState {
  customers: Customer[];
  orders: Order[];
  payments: Payment[];
  loading: boolean;
  initialized: boolean;
  initializeData: (userId: string) => Promise<void>;
  addCustomer: (customer: Omit<Customer, "id" | "createdAt">, userId: string) => Promise<void>;
  updateCustomer: (id: string, data: Partial<Customer>) => Promise<void>;
  deleteCustomer: (id: string) => void;
  addOrder: (order: Omit<Order, "id" | "orderNumber">, userId: string) => Promise<void>;
  updateOrder: (id: string, data: Partial<Order>) => void;
  updateOrderStatus: (id: string, status: Order["status"]) => void;
  deleteOrder: (id: string) => void;
  addPayment: (payment: Omit<Payment, "id">, userId: string) => void;
  getCustomerDebt: (customerId: string) => number;
  getCustomerOrders: (customerId: string) => Order[];
  getTotalDebt: () => number;
  getTotalSales: () => number;
  getDebtors: () => Array<{ customer: Customer; debt: number; orders: Order[] }>;
}

export const useDataStore = create<DataState>()((set, get) => ({
  customers: [],
  orders: [],
  payments: [],
  loading: true,
  initialized: false,

  initializeData: async (userId: string) => {
    if (get().initialized) { set({ loading: false }); return; }
    try {
      const [custRes, ordRes, payRes] = await Promise.all([
        supabase.from("customers").select("*").eq("user_id", userId).order("created_at", { ascending: false }),
        supabase.from("orders").select("*, order_items(*)").eq("user_id", userId).order("created_at", { ascending: false }),
        supabase.from("payments").select("*").eq("user_id", userId).order("date", { ascending: false }),
      ]);

      const customers = (custRes.data || []).map((c: any) => ({
        id: c.id, name: c.name, phone: c.phone, email: c.email, city: c.city,
        address: c.address, notes: c.notes, createdAt: c.created_at?.split("T")[0] || "",
        source: c.source || "", addedById: c.added_by_id || "", addedByName: c.added_by_name || "",
      }));

      const orders = (ordRes.data || []).map((o: any) => ({
        id: o.id, orderNumber: o.order_number, customerId: o.customer_id,
        customerName: o.customer_name, customerPhone: o.customer_phone,
        status: o.status, paymentStatus: o.payment_status,
        items: (o.order_items || []).map((i: any) => ({
          id: i.id, productCode: i.product_code, productName: i.product_name,
          quantity: i.quantity, unitPrice: i.unit_price, buyPrice: i.buy_price, total: i.total,
        })),
        subtotal: Number(o.subtotal), discount: Number(o.discount), total: Number(o.total),
        paid: Number(o.paid), remaining: Number(o.remaining),
        dueDate: o.due_date, notes: o.notes, repId: o.rep_id, repName: o.rep_name,
        createdAt: o.created_at?.split("T")[0] || "",
      }));

      const payments = (payRes.data || []).map((p: any) => ({
        id: p.id, orderId: p.order_id, customerId: p.customer_id,
        customerName: p.customer_name, amount: Number(p.amount),
        method: p.method, date: p.date, notes: p.notes,
        receiptUrl: p.receipt_url || "",
        recordedById: p.recorded_by_id || "",
        recordedByName: p.recorded_by_name || "",
      }));

      set({ customers, orders, payments, loading: false, initialized: true });
    } catch (err) {
      console.error("Failed to load data:", err);
      set({ loading: false, initialized: true });
    }
  },

  addCustomer: async (data, userId) => {
    const { data: row, error } = await supabase.from("customers").insert({
      user_id: userId, name: data.name, phone: data.phone, email: data.email || "",
      city: data.city || "", address: data.address || "", notes: data.notes || "",
    }).select().single();
    if (error) { toast.error("فشل إضافة العميل: " + error.message); return; }
    const newC: Customer = { id: row.id, name: row.name, phone: row.phone, email: row.email, city: row.city, address: row.address, notes: row.notes, createdAt: row.created_at?.split("T")[0] || "" };
    set((s) => ({ customers: [newC, ...s.customers] }));
  },

  updateCustomer: async (id, data) => {
    const payload: any = {};
    if (data.name !== undefined) payload.name = data.name;
    if (data.phone !== undefined) payload.phone = data.phone;
    if (data.city !== undefined) payload.city = data.city;
    if (data.notes !== undefined) payload.notes = data.notes;
    await supabase.from("customers").update(payload).eq("id", id);
    set((s) => ({ customers: s.customers.map((c) => (c.id === id ? { ...c, ...data } : c)) }));
  },

  deleteCustomer: async (id) => {
    await supabase.from("customers").delete().eq("id", id);
    set((s) => ({ customers: s.customers.filter((c) => c.id !== id) }));
  },

  addOrder: async (orderData, userId) => {
    const orderNumber = generateOrderNumber();
    const { data: row, error } = await supabase.from("orders").insert({
      user_id: userId, order_number: orderNumber, customer_id: orderData.customerId,
      customer_name: orderData.customerName, customer_phone: orderData.customerPhone,
      status: orderData.status, payment_status: orderData.paymentStatus,
      subtotal: orderData.subtotal, discount: orderData.discount, total: orderData.total,
      paid: orderData.paid, remaining: orderData.remaining,
      due_date: orderData.dueDate, notes: orderData.notes,
      rep_id: orderData.repId, rep_name: orderData.repName,
    }).select().single();

    if (error) { toast.error("فشل إنشاء الطلب: " + error.message); return; }

    if (orderData.items.length > 0) {
      await supabase.from("order_items").insert(
        orderData.items.map((i) => ({
          order_id: row.id, product_code: i.productCode || "", product_name: i.productName,
          quantity: i.quantity, unit_price: i.unitPrice, buy_price: i.buyPrice || 0, total: i.total,
        }))
      );
    }

    for (const item of orderData.items) {
      if (item.productCode) {
        await supabase.rpc("decrement_stock", { p_code: item.productCode, p_qty: item.quantity }).then(() => {});
      }
    }

    const newOrder: Order = {
      id: row.id, orderNumber, customerId: orderData.customerId,
      customerName: orderData.customerName, customerPhone: orderData.customerPhone,
      items: orderData.items, status: orderData.status, paymentStatus: orderData.paymentStatus,
      subtotal: orderData.subtotal, discount: orderData.discount, total: orderData.total,
      paid: orderData.paid, remaining: orderData.remaining,
      dueDate: orderData.dueDate, notes: orderData.notes,
      repId: orderData.repId, repName: orderData.repName,
      createdAt: row.created_at?.split("T")[0] || new Date().toISOString().split("T")[0],
    };
    set((s) => ({ orders: [newOrder, ...s.orders] }));
  },

  updateOrder: async (id, data) => {
    const payload: any = {};
    if (data.status) payload.status = data.status;
    if (data.paymentStatus) payload.payment_status = data.paymentStatus;
    if (data.paid !== undefined) payload.paid = data.paid;
    if (data.remaining !== undefined) payload.remaining = data.remaining;
    if (data.notes !== undefined) payload.notes = data.notes;
    await supabase.from("orders").update(payload).eq("id", id);
    set((s) => ({ orders: s.orders.map((o) => (o.id === id ? { ...o, ...data } : o)) }));
  },

  updateOrderStatus: async (id, status) => {
    await supabase.from("orders").update({ status }).eq("id", id);
    set((s) => ({ orders: s.orders.map((o) => (o.id === id ? { ...o, status } : o)) }));
  },

  deleteOrder: async (id) => {
    await supabase.from("order_items").delete().eq("order_id", id);
    await supabase.from("orders").delete().eq("id", id);
    set((s) => ({ orders: s.orders.filter((o) => o.id !== id) }));
  },

  addPayment: async (paymentData, userId) => {
    const { data: row, error } = await supabase.from("payments").insert({
      user_id: userId, order_id: paymentData.orderId, customer_id: paymentData.customerId,
      customer_name: paymentData.customerName, amount: paymentData.amount,
      method: paymentData.method, date: paymentData.date, notes: paymentData.notes || "",
      receipt_url: paymentData.receiptUrl || "",
      recorded_by_id: paymentData.recordedById || userId,
      recorded_by_name: paymentData.recordedByName || "",
    }).select().single();
    if (error) { toast.error("فشل تسجيل الدفعة"); return; }

    const newPayment: Payment = { id: row.id, ...paymentData };
    set((state) => {
      const order = state.orders.find((o) => o.id === paymentData.orderId);
      if (!order) return { payments: [newPayment, ...state.payments] };
      const newPaid = order.paid + paymentData.amount;
      const newRemaining = Math.max(0, order.total - newPaid);
      const paymentStatus = newRemaining === 0 ? "paid" as const : "partial" as const;
      supabase.from("orders").update({ paid: newPaid, remaining: newRemaining, payment_status: paymentStatus }).eq("id", paymentData.orderId);
      return {
        payments: [newPayment, ...state.payments],
        orders: state.orders.map((o) => o.id === paymentData.orderId ? { ...o, paid: newPaid, remaining: newRemaining, paymentStatus } : o),
      };
    });
  },

  getCustomerDebt: (customerId) => get().orders.filter((o) => o.customerId === customerId && o.remaining > 0).reduce((sum, o) => sum + o.remaining, 0),
  getCustomerOrders: (customerId) => get().orders.filter((o) => o.customerId === customerId),
  getTotalDebt: () => get().orders.reduce((sum, o) => sum + o.remaining, 0),
  getTotalSales: () => get().orders.reduce((sum, o) => sum + o.total, 0),

  getDebtors: () => {
    const state = get();
    const debtorMap = new Map<string, { debt: number; orders: Order[] }>();
    state.orders.filter((o) => o.remaining > 0).forEach((order) => {
      const existing = debtorMap.get(order.customerId);
      if (existing) { existing.debt += order.remaining; existing.orders.push(order); }
      else debtorMap.set(order.customerId, { debt: order.remaining, orders: [order] });
    });
    return Array.from(debtorMap.entries())
      .map(([customerId, data]) => {
        const customer = state.customers.find((c) => c.id === customerId);
        if (!customer) return null;
        return { customer, ...data };
      })
      .filter(Boolean)
      .sort((a, b) => b!.debt - a!.debt) as Array<{ customer: Customer; debt: number; orders: Order[] }>;
  },
}));

import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import type { Expense, ExpenseCategory } from "@/types";
import { toast } from "sonner";

interface ExpenseState {
  expenses: Expense[];
  loading: boolean;
  initialized: boolean;
  initializeData: (userId: string) => Promise<void>;
  addExpense: (e: Omit<Expense, "id">, userId: string) => Promise<void>;
  updateExpense: (id: string, data: Partial<Expense>) => void;
  deleteExpense: (id: string) => void;
  getTotalExpenses: () => number;
  getFixedExpenses: () => number;
  getVariableExpenses: () => number;
  getExpensesByCategory: () => Record<ExpenseCategory, number>;
  getMonthlyExpenses: (year: number, month: number) => Expense[];
  getTotalExpensesForMonth: (year: number, month: number) => number;
}

export const useExpenseStore = create<ExpenseState>()((set, get) => ({
  expenses: [],
  loading: true,
  initialized: false,

  initializeData: async (userId: string) => {
    if (get().initialized) return;
    const { data } = await supabase.from("expenses").select("*").eq("user_id", userId).order("date", { ascending: false });
    const expenses = (data || []).map((e: any) => ({
      id: e.id, category: e.category as ExpenseCategory, description: e.description,
      amount: Number(e.amount), date: e.date, notes: e.notes, isFixed: e.is_fixed,
    }));
    set({ expenses, loading: false, initialized: true });
  },

  addExpense: async (data, userId) => {
    const { data: row, error } = await supabase.from("expenses").insert({
      user_id: userId, category: data.category, description: data.description,
      amount: data.amount, date: data.date, notes: data.notes || "", is_fixed: data.isFixed || false,
    }).select().single();
    if (error) { toast.error("فشل تسجيل المصروف"); return; }
    set((s) => ({ expenses: [{ id: row.id, ...data }, ...s.expenses] }));
  },

  updateExpense: async (id, data) => {
    const payload: any = {};
    if (data.amount !== undefined) payload.amount = data.amount;
    if (data.description !== undefined) payload.description = data.description;
    if (data.category !== undefined) payload.category = data.category;
    await supabase.from("expenses").update(payload).eq("id", id);
    set((s) => ({ expenses: s.expenses.map((e) => (e.id === id ? { ...e, ...data } : e)) }));
  },

  deleteExpense: async (id) => {
    await supabase.from("expenses").delete().eq("id", id);
    set((s) => ({ expenses: s.expenses.filter((e) => e.id !== id) }));
  },

  getTotalExpenses: () => get().expenses.reduce((s, e) => s + e.amount, 0),
  getFixedExpenses: () => get().expenses.filter((e) => e.isFixed).reduce((s, e) => s + e.amount, 0),
  getVariableExpenses: () => get().expenses.filter((e) => !e.isFixed).reduce((s, e) => s + e.amount, 0),

  getExpensesByCategory: () => {
    const result = {} as Record<ExpenseCategory, number>;
    get().expenses.forEach((e) => { result[e.category] = (result[e.category] || 0) + e.amount; });
    return result;
  },

  getMonthlyExpenses: (year, month) => get().expenses.filter((e) => { const d = new Date(e.date); return d.getFullYear() === year && d.getMonth() === month; }),
  getTotalExpensesForMonth: (year, month) => get().getMonthlyExpenses(year, month).reduce((s, e) => s + e.amount, 0),
}));

import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import type { SMSNotification } from "@/types";
import { SMS_TEMPLATES } from "@/constants/config";
import { getStatusLabel } from "@/lib/formatters";

interface NotificationState {
  notifications: SMSNotification[];
  initialized: boolean;
  initializeData: (userId: string) => Promise<void>;
  addNotification: (n: Omit<SMSNotification, "id" | "sentAt">, userId: string) => void;
  sendStatusChangeSMS: (recipientName: string, recipientPhone: string, orderNumber: string, newStatus: string, orderId: string, userId: string) => void;
  sendPaymentSMS: (recipientName: string, recipientPhone: string, amount: number, remaining: number, orderId: string, userId: string) => void;
  sendDueReminderSMS: (recipientName: string, recipientPhone: string, orderNumber: string, dueDate: string, orderId: string, userId: string) => void;
  getNotifications: () => SMSNotification[];
  clearNotifications: () => void;
}

export const useNotificationStore = create<NotificationState>()((set, get) => ({
  notifications: [],
  initialized: false,

  initializeData: async (userId: string) => {
    if (get().initialized) return;
    const { data } = await supabase.from("notifications").select("*").eq("user_id", userId).order("sent_at", { ascending: false }).limit(200);
    const notifications = (data || []).map((n: any) => ({
      id: n.id, type: n.type, recipientName: n.recipient_name, recipientPhone: n.recipient_phone,
      message: n.message, status: n.status, orderId: n.order_id, sentAt: n.sent_at,
    }));
    set({ notifications, initialized: true });
  },

  addNotification: async (data, userId) => {
    const sentAt = new Date().toISOString();
    const { data: row } = await supabase.from("notifications").insert({
      user_id: userId, type: data.type, recipient_name: data.recipientName,
      recipient_phone: data.recipientPhone, message: data.message, status: data.status, order_id: data.orderId,
    }).select().single();
    const notif: SMSNotification = { ...data, id: row?.id || crypto.randomUUID(), sentAt };
    set((s) => ({ notifications: [notif, ...s.notifications].slice(0, 200) }));
  },

  sendStatusChangeSMS: (recipientName, recipientPhone, orderNumber, newStatus, orderId, userId) => {
    const message = SMS_TEMPLATES.statusChange(recipientName, orderNumber, getStatusLabel(newStatus));
    get().addNotification({ type: "status_change", recipientName, recipientPhone, message, status: "sent", orderId }, userId);
    const encoded = encodeURIComponent(message);
    const phone = recipientPhone.replace(/\D/g, "");
    window.open(`https://wa.me/${phone.startsWith("967") ? phone : "967" + phone}?text=${encoded}`, "_blank");
  },

  sendPaymentSMS: (recipientName, recipientPhone, amount, remaining, orderId, userId) => {
    const message = SMS_TEMPLATES.paymentReceived(recipientName, amount, remaining);
    get().addNotification({ type: "payment", recipientName, recipientPhone, message, status: "sent", orderId }, userId);
    const encoded = encodeURIComponent(message);
    const phone = recipientPhone.replace(/\D/g, "");
    window.open(`https://wa.me/${phone.startsWith("967") ? phone : "967" + phone}?text=${encoded}`, "_blank");
  },

  sendDueReminderSMS: (recipientName, recipientPhone, orderNumber, dueDate, orderId, userId) => {
    const message = SMS_TEMPLATES.dueReminder(recipientName, orderNumber, dueDate);
    get().addNotification({ type: "due_reminder", recipientName, recipientPhone, message, status: "sent", orderId }, userId);
    const encoded = encodeURIComponent(message);
    const phone = recipientPhone.replace(/\D/g, "");
    window.open(`https://wa.me/${phone.startsWith("967") ? phone : "967" + phone}?text=${encoded}`, "_blank");
  },

  getNotifications: () => get().notifications,
  clearNotifications: () => set({ notifications: [] }),
}));

