import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import { toast } from "sonner";

export interface Partner {
  id: string;
  partnerKey: "first" | "second" | "worker";
  partnerName: string;
  partnerEmail: string;
  percentage: number;
  isActive: boolean;
  notes: string;
}

interface PartnersState {
  partners: Partner[];
  loading: boolean;
  initialized: boolean;
  initializePartners: (userId: string) => Promise<void>;
  refreshPartners: (userId: string) => Promise<void>;
  upsertPartner: (userId: string, partner: Omit<Partner, "id">) => Promise<void>;
  updatePartner: (id: string, data: Partial<Partner>) => Promise<void>;
  toggleActive: (id: string) => Promise<void>;
  removePartner: (id: string) => Promise<void>;
  distributeProfit: (totalRevenue: number, totalExpenses: number) => {
    netProfit: number;
    distributions: Array<{ partner: Partner; amount: number }>;
    undistributed: number;
  };
}

const DEFAULT_PARTNERS: Array<Omit<Partner, "id">> = [
  { partnerKey: "first", partnerName: "الطرف الأول", partnerEmail: "", percentage: 0, isActive: true, notes: "" },
  { partnerKey: "second", partnerName: "الطرف الثاني", partnerEmail: "", percentage: 0, isActive: true, notes: "" },
  { partnerKey: "worker", partnerName: "الطرف الثالث (العامل)", partnerEmail: "", percentage: 0, isActive: false, notes: "" },
];

export const usePartnersStore = create<PartnersState>()((set, get) => ({
  partners: [],
  loading: true,
  initialized: false,

  initializePartners: async (userId: string) => {
    if (get().initialized) return;
    await get().refreshPartners(userId);
  },

  refreshPartners: async (userId: string) => {
    const { data } = await supabase.from("partners_config").select("*").eq("user_id", userId).order("partner_key");

    let partners: Partner[] = (data || []).map((r: { id: string; partner_key: string; partner_name: string; partner_email: string; percentage: string; is_active: boolean; notes: string }) => ({
      id: r.id,
      partnerKey: r.partner_key as Partner["partnerKey"],
      partnerName: r.partner_name,
      partnerEmail: r.partner_email,
      percentage: Number(r.percentage) || 0,
      isActive: r.is_active,
      notes: r.notes,
    }));

    // Ensure the 3 default partners exist
    for (const def of DEFAULT_PARTNERS) {
      if (!partners.find((p) => p.partnerKey === def.partnerKey)) {
        const { data: inserted } = await supabase.from("partners_config").insert({
          user_id: userId,
          partner_key: def.partnerKey,
          partner_name: def.partnerName,
          partner_email: def.partnerEmail,
          percentage: def.percentage,
          is_active: def.isActive,
          notes: def.notes,
        }).select().single();
        if (inserted) {
          partners.push({
            id: inserted.id,
            partnerKey: def.partnerKey,
            partnerName: def.partnerName,
            partnerEmail: def.partnerEmail,
            percentage: def.percentage,
            isActive: def.isActive,
            notes: def.notes,
          });
        }
      }
    }

    // Order first, second, worker
    const orderMap: Record<string, number> = { first: 1, second: 2, worker: 3 };
    partners.sort((a, b) => (orderMap[a.partnerKey] || 99) - (orderMap[b.partnerKey] || 99));

    set({ partners, loading: false, initialized: true });
  },

  upsertPartner: async (userId, partner) => {
    const { data, error } = await supabase.from("partners_config").upsert({
      user_id: userId,
      partner_key: partner.partnerKey,
      partner_name: partner.partnerName,
      partner_email: partner.partnerEmail,
      percentage: partner.percentage,
      is_active: partner.isActive,
      notes: partner.notes,
    }, { onConflict: "user_id,partner_key" }).select().single();

    if (error) { toast.error("فشل الحفظ: " + error.message); return; }
    await get().refreshPartners(userId);
  },

  updatePartner: async (id, data) => {
    const payload: Record<string, unknown> = {};
    if (data.partnerName !== undefined) payload.partner_name = data.partnerName;
    if (data.partnerEmail !== undefined) payload.partner_email = data.partnerEmail;
    if (data.percentage !== undefined) payload.percentage = data.percentage;
    if (data.isActive !== undefined) payload.is_active = data.isActive;
    if (data.notes !== undefined) payload.notes = data.notes;

    const { error } = await supabase.from("partners_config").update(payload).eq("id", id);
    if (error) { toast.error("فشل التحديث: " + error.message); return; }
    set((s) => ({ partners: s.partners.map((p) => p.id === id ? { ...p, ...data } : p) }));
  },

  toggleActive: async (id) => {
    const target = get().partners.find((p) => p.id === id);
    if (!target) return;
    const newActive = !target.isActive;
    await supabase.from("partners_config").update({ is_active: newActive }).eq("id", id);
    set((s) => ({ partners: s.partners.map((p) => p.id === id ? { ...p, isActive: newActive } : p) }));
  },

  removePartner: async (id) => {
    await supabase.from("partners_config").delete().eq("id", id);
    set((s) => ({ partners: s.partners.filter((p) => p.id !== id) }));
  },

  distributeProfit: (totalRevenue, totalExpenses) => {
    const netProfit = totalRevenue - totalExpenses;
    const active = get().partners.filter((p) => p.isActive);
    const totalPercent = active.reduce((s, p) => s + p.percentage, 0);
    const distributions = active.map((partner) => ({
      partner,
      amount: netProfit > 0 ? (netProfit * partner.percentage) / 100 : 0,
    }));
    const distributedTotal = distributions.reduce((s, d) => s + d.amount, 0);
    return {
      netProfit,
      distributions,
      undistributed: netProfit - distributedTotal,
      totalPercent,
    } as {
      netProfit: number;
      distributions: Array<{ partner: Partner; amount: number }>;
      undistributed: number;
      totalPercent: number;
    };
  },
}));

import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import type { SalesRep, RepCommission } from "@/types";
import { toast } from "sonner";

interface RepState {
  reps: SalesRep[];
  commissions: RepCommission[];
  loading: boolean;
  initialized: boolean;
  initializeData: (userId: string) => Promise<void>;
  addRep: (r: Omit<SalesRep, "id" | "createdAt">, userId: string) => Promise<void>;
  updateRep: (id: string, data: Partial<SalesRep>) => void;
  deleteRep: (id: string) => void;
  addCommission: (c: Omit<RepCommission, "id">) => Promise<void>;
  markCommissionPaid: (id: string) => void;
  deleteCommission: (id: string) => void;
  getRepCommissions: (repId: string) => RepCommission[];
  getRepTotalEarned: (repId: string) => number;
  getRepTotalPaid: (repId: string) => number;
  getRepTotalPending: (repId: string) => number;
  getTotalCommissions: () => number;
  getTotalPendingCommissions: () => number;
}

export const useRepStore = create<RepState>()((set, get) => ({
  reps: [],
  commissions: [],
  loading: true,
  initialized: false,

  initializeData: async (userId: string) => {
    if (get().initialized) return;
    const [repRes, comRes] = await Promise.all([
      supabase.from("sales_reps").select("*").eq("user_id", userId).order("created_at", { ascending: false }),
      supabase.from("rep_commissions").select("*").order("date", { ascending: false }),
    ]);
    const reps = (repRes.data || []).map((r: any) => ({
      id: r.id, name: r.name, phone: r.phone, email: r.email, city: r.city,
      commissionRate: Number(r.commission_rate), notes: r.notes, isActive: r.is_active, createdAt: r.created_at?.split("T")[0] || "",
    }));
    const commissions = (comRes.data || []).map((c: any) => ({
      id: c.id, repId: c.rep_id, repName: c.rep_name, orderId: c.order_id, orderNumber: c.order_number,
      orderTotal: Number(c.order_total), commissionAmount: Number(c.commission_amount),
      shippingDeduction: Number(c.shipping_deduction), netCommission: Number(c.net_commission),
      isPaid: c.is_paid, date: c.date, notes: c.notes,
    }));
    set({ reps, commissions, loading: false, initialized: true });
  },

  addRep: async (data, userId) => {
    const { data: row, error } = await supabase.from("sales_reps").insert({
      user_id: userId, name: data.name, phone: data.phone, email: data.email || "",
      city: data.city || "", commission_rate: data.commissionRate, notes: data.notes || "", is_active: data.isActive !== false,
    }).select().single();
    if (error) { toast.error("فشل إضافة المندوب"); return; }
    set((s) => ({ reps: [{ id: row.id, ...data, createdAt: row.created_at?.split("T")[0] || "" }, ...s.reps] }));
  },

  updateRep: async (id, data) => {
    const payload: any = {};
    if (data.name) payload.name = data.name;
    if (data.isActive !== undefined) payload.is_active = data.isActive;
    if (data.commissionRate !== undefined) payload.commission_rate = data.commissionRate;
    await supabase.from("sales_reps").update(payload).eq("id", id);
    set((s) => ({ reps: s.reps.map((r) => (r.id === id ? { ...r, ...data } : r)) }));
  },

  deleteRep: async (id) => {
    await supabase.from("sales_reps").delete().eq("id", id);
    set((s) => ({ reps: s.reps.filter((r) => r.id !== id) }));
  },

  addCommission: async (data) => {
    const { data: row, error } = await supabase.from("rep_commissions").insert({
      rep_id: data.repId, rep_name: data.repName, order_id: data.orderId, order_number: data.orderNumber,
      order_total: data.orderTotal, commission_amount: data.commissionAmount,
      shipping_deduction: data.shippingDeduction, net_commission: data.netCommission,
      is_paid: data.isPaid, date: data.date, notes: data.notes || "",
    }).select().single();
    if (error) { console.error(error); return; }
    set((s) => ({ commissions: [{ id: row.id, ...data }, ...s.commissions] }));
  },

  markCommissionPaid: async (id) => {
    await supabase.from("rep_commissions").update({ is_paid: true }).eq("id", id);
    set((s) => ({ commissions: s.commissions.map((c) => (c.id === id ? { ...c, isPaid: true } : c)) }));
  },

  deleteCommission: async (id) => {
    await supabase.from("rep_commissions").delete().eq("id", id);
    set((s) => ({ commissions: s.commissions.filter((c) => c.id !== id) }));
  },

  getRepCommissions: (repId) => get().commissions.filter((c) => c.repId === repId).sort((a, b) => b.date.localeCompare(a.date)),
  getRepTotalEarned: (repId) => get().commissions.filter((c) => c.repId === repId).reduce((s, c) => s + c.netCommission, 0),
  getRepTotalPaid: (repId) => get().commissions.filter((c) => c.repId === repId && c.isPaid).reduce((s, c) => s + c.netCommission, 0),
  getRepTotalPending: (repId) => get().commissions.filter((c) => c.repId === repId && !c.isPaid).reduce((s, c) => s + c.netCommission, 0),
  getTotalCommissions: () => get().commissions.reduce((s, c) => s + c.netCommission, 0),
  getTotalPendingCommissions: () => get().commissions.filter((c) => !c.isPaid).reduce((s, c) => s + c.netCommission, 0),
}));

import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import type { Return } from "@/types";
import { toast } from "sonner";

interface ReturnState {
  returns: Return[];
  loading: boolean;
  initialized: boolean;
  initializeData: (userId: string) => Promise<void>;
  addReturn: (r: Omit<Return, "id">, userId: string) => Promise<void>;
  updateReturnStatus: (id: string, status: Return["status"]) => void;
  deleteReturn: (id: string) => void;
  getCustomerReturns: () => Return[];
  getSupplierReturns: () => Return[];
  getTotalCustomerReturns: () => number;
  getTotalSupplierReturns: () => number;
}

export const useReturnStore = create<ReturnState>()((set, get) => ({
  returns: [],
  loading: true,
  initialized: false,

  initializeData: async (userId: string) => {
    if (get().initialized) return;
    const [retRes, itemsRes] = await Promise.all([
      supabase.from("returns").select("*").eq("user_id", userId).order("date", { ascending: false }),
      supabase.from("return_items").select("*"),
    ]);
    const itemsByReturn = new Map<string, any[]>();
    (itemsRes.data || []).forEach((item: any) => {
      const list = itemsByReturn.get(item.return_id) || [];
      list.push({ id: item.id, productCode: item.product_code, productName: item.product_name, quantity: item.quantity, unitPrice: Number(item.unit_price), total: Number(item.total) });
      itemsByReturn.set(item.return_id, list);
    });
    const returns = (retRes.data || []).map((r: any) => ({
      id: r.id, type: r.type, orderId: r.order_id, orderNumber: r.order_number,
      customerId: r.customer_id, customerName: r.customer_name,
      supplierId: r.supplier_id, supplierName: r.supplier_name,
      items: itemsByReturn.get(r.id) || [], reason: r.reason,
      totalAmount: Number(r.total_amount), status: r.status, date: r.date, notes: r.notes,
    }));
    set({ returns, loading: false, initialized: true });
  },

  addReturn: async (data, userId) => {
    const { data: row, error } = await supabase.from("returns").insert({
      user_id: userId, type: data.type, order_id: data.orderId, order_number: data.orderNumber,
      customer_id: data.customerId, customer_name: data.customerName || "",
      supplier_id: data.supplierId, supplier_name: data.supplierName || "",
      reason: data.reason, total_amount: data.totalAmount, status: data.status, date: data.date, notes: data.notes || "",
    }).select().single();
    if (error) { toast.error("فشل تسجيل المرتجع"); return; }

    if (data.items.length > 0) {
      await supabase.from("return_items").insert(
        data.items.map((i) => ({ return_id: row.id, product_code: i.productCode || "", product_name: i.productName, quantity: i.quantity, unit_price: i.unitPrice, total: i.total }))
      );
    }
    set((s) => ({ returns: [{ id: row.id, ...data }, ...s.returns] }));
  },

  updateReturnStatus: async (id, status) => {
    await supabase.from("returns").update({ status }).eq("id", id);
    set((s) => ({ returns: s.returns.map((r) => (r.id === id ? { ...r, status } : r)) }));
  },

  deleteReturn: async (id) => {
    await supabase.from("return_items").delete().eq("return_id", id);
    await supabase.from("returns").delete().eq("id", id);
    set((s) => ({ returns: s.returns.filter((r) => r.id !== id) }));
  },

  getCustomerReturns: () => get().returns.filter((r) => r.type === "customer"),
  getSupplierReturns: () => get().returns.filter((r) => r.type === "supplier"),
  getTotalCustomerReturns: () => get().returns.filter((r) => r.type === "customer").reduce((s, r) => s + r.totalAmount, 0),
  getTotalSupplierReturns: () => get().returns.filter((r) => r.type === "supplier").reduce((s, r) => s + r.totalAmount, 0),
}));

import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import { toast } from "sonner";

export interface DiscountRule {
  id: string;
  name: string;
  type: "governorate_discount" | "amount_discount" | "product_discount";
  conditionField: string;
  conditionValue: string;
  discountType: "fixed" | "percentage";
  discountValue: number;
  isActive: boolean;
  priority: number;
  createdAt: string;
}

interface RulesState {
  rules: DiscountRule[];
  initialized: boolean;
  loading: boolean;
  initializeRules: (userId: string) => Promise<void>;
  addRule: (rule: Omit<DiscountRule, "id" | "createdAt">, userId: string) => Promise<void>;
  updateRule: (id: string, data: Partial<DiscountRule>) => Promise<void>;
  toggleRule: (id: string) => Promise<void>;
  deleteRule: (id: string) => Promise<void>;
  killAllRules: () => Promise<void>;
  calculateDiscount: (governorate: string, orderTotal: number) => { totalDiscount: number; appliedRules: string[] };
}

export const useRulesStore = create<RulesState>()((set, get) => ({
  rules: [],
  initialized: false,
  loading: true,

  initializeRules: async (userId: string) => {
    if (get().initialized) return;
    const { data } = await supabase.from("discount_rules").select("*").eq("user_id", userId).order("priority", { ascending: true });
    const rules = (data || []).map((r: any) => ({
      id: r.id, name: r.name, type: r.type, conditionField: r.condition_field,
      conditionValue: r.condition_value, discountType: r.discount_type,
      discountValue: Number(r.discount_value), isActive: r.is_active,
      priority: r.priority, createdAt: r.created_at,
    }));
    set({ rules, initialized: true, loading: false });
  },

  addRule: async (rule, userId) => {
    const { data: row, error } = await supabase.from("discount_rules").insert({
      user_id: userId, name: rule.name, type: rule.type,
      condition_field: rule.conditionField, condition_value: rule.conditionValue,
      discount_type: rule.discountType, discount_value: rule.discountValue,
      is_active: rule.isActive, priority: rule.priority,
    }).select().single();
    if (error) { toast.error("فشل إنشاء القاعدة"); return; }
    const newRule: DiscountRule = { ...rule, id: row.id, createdAt: row.created_at };
    set((s) => ({ rules: [...s.rules, newRule] }));
    toast.success("تم إنشاء القاعدة");
  },

  updateRule: async (id, data) => {
    const payload: any = {};
    if (data.name !== undefined) payload.name = data.name;
    if (data.conditionValue !== undefined) payload.condition_value = data.conditionValue;
    if (data.discountType !== undefined) payload.discount_type = data.discountType;
    if (data.discountValue !== undefined) payload.discount_value = data.discountValue;
    if (data.isActive !== undefined) payload.is_active = data.isActive;
    if (data.priority !== undefined) payload.priority = data.priority;
    await supabase.from("discount_rules").update(payload).eq("id", id);
    set((s) => ({ rules: s.rules.map((r) => (r.id === id ? { ...r, ...data } : r)) }));
  },

  toggleRule: async (id) => {
    const rule = get().rules.find((r) => r.id === id);
    if (!rule) return;
    const newActive = !rule.isActive;
    await supabase.from("discount_rules").update({ is_active: newActive }).eq("id", id);
    set((s) => ({ rules: s.rules.map((r) => (r.id === id ? { ...r, isActive: newActive } : r)) }));
    toast.success(newActive ? "تم تفعيل القاعدة" : "تم تعطيل القاعدة");
  },

  deleteRule: async (id) => {
    await supabase.from("discount_rules").delete().eq("id", id);
    set((s) => ({ rules: s.rules.filter((r) => r.id !== id) }));
    toast.success("تم حذف القاعدة");
  },

  killAllRules: async () => {
    const activeRules = get().rules.filter((r) => r.isActive);
    for (const rule of activeRules) {
      await supabase.from("discount_rules").update({ is_active: false }).eq("id", rule.id);
    }
    set((s) => ({ rules: s.rules.map((r) => ({ ...r, isActive: false })) }));
    toast.success("تم تعطيل جميع القواعد (إيقاف طارئ)");
  },

  calculateDiscount: (governorate, orderTotal) => {
    const activeRules = get().rules.filter((r) => r.isActive).sort((a, b) => a.priority - b.priority);
    let totalDiscount = 0;
    const appliedRules: string[] = [];

    for (const rule of activeRules) {
      if (rule.type === "governorate_discount") {
        if (governorate && rule.conditionValue.split(",").map((v) => v.trim()).includes(governorate)) {
          const discount = rule.discountType === "fixed" ? rule.discountValue : (orderTotal * rule.discountValue) / 100;
          totalDiscount += discount;
          appliedRules.push(`${rule.name}: -${rule.discountType === "fixed" ? discount + " ر.ي" : rule.discountValue + "%"}`);
        }
      } else if (rule.type === "amount_discount") {
        const threshold = parseFloat(rule.conditionValue);
        if (orderTotal >= threshold) {
          const discount = rule.discountType === "fixed" ? rule.discountValue : (orderTotal * rule.discountValue) / 100;
          totalDiscount += discount;
          appliedRules.push(`${rule.name}: -${rule.discountType === "fixed" ? discount + " ر.ي" : rule.discountValue + "%"}`);
        }
      }
    }

    return { totalDiscount, appliedRules };
  },
}));

import { create } from "zustand";
import { supabase } from "@/lib/supabase";
import type { Supplier, SupplierTransaction } from "@/types";
import { toast } from "sonner";

interface SupplierState {
  suppliers: Supplier[];
  transactions: SupplierTransaction[];
  loading: boolean;
  initialized: boolean;
  initializeData: (userId: string) => Promise<void>;
  addSupplier: (s: Omit<Supplier, "id" | "createdAt">, userId: string) => Promise<void>;
  updateSupplier: (id: string, data: Partial<Supplier>) => void;
  deleteSupplier: (id: string) => void;
  addTransaction: (t: Omit<SupplierTransaction, "id">) => Promise<void>;
  deleteTransaction: (id: string) => void;
  getSupplierBalance: (supplierId: string) => { totalPurchases: number; totalPayments: number; totalReturns: number; remaining: number; totalPieces: number; fabricByUnit: Record<string, number> };
  getSupplierTransactions: (supplierId: string) => SupplierTransaction[];
  getTotalSupplierDebt: () => number;
  getTotalFabricByUnit: () => Record<string, number>;
}

export const useSupplierStore = create<SupplierState>()((set, get) => ({
  suppliers: [],
  transactions: [],
  loading: true,
  initialized: false,

  initializeData: async (userId: string) => {
    if (get().initialized) return;
    const [supRes, txRes] = await Promise.all([
      supabase.from("suppliers").select("*").eq("user_id", userId).order("created_at", { ascending: false }),
      supabase.from("supplier_transactions").select("*").order("date", { ascending: false }),
    ]);
    const suppliers = (supRes.data || []).map((s: any) => ({
      id: s.id, name: s.name, phone: s.phone, email: s.email, company: s.company, city: s.city, notes: s.notes, createdAt: s.created_at?.split("T")[0] || "",
    }));
    const transactions = (txRes.data || []).map((t: any) => ({
      id: t.id, supplierId: t.supplier_id, supplierName: t.supplier_name, type: t.type,
      amount: Number(t.amount), pieces: t.pieces, fabricType: t.fabric_type,
      fabricUnit: t.fabric_unit || "متر", fabricQuantity: Number(t.fabric_quantity || 0),
      date: t.date, notes: t.notes,
    }));
    set({ suppliers, transactions, loading: false, initialized: true });
  },

  addSupplier: async (data, userId) => {
    const { data: row, error } = await supabase.from("suppliers").insert({
      user_id: userId, name: data.name, phone: data.phone, email: data.email || "",
      company: data.company || "", city: data.city || "", notes: data.notes || "",
    }).select().single();
    if (error) { toast.error("فشل إضافة المورد"); return; }
    set((s) => ({ suppliers: [{ id: row.id, ...data, createdAt: row.created_at?.split("T")[0] || "" }, ...s.suppliers] }));
  },

  updateSupplier: async (id, data) => {
    const payload: any = {};
    if (data.name) payload.name = data.name;
    if (data.phone) payload.phone = data.phone;
    if (data.company) payload.company = data.company;
    if (data.city) payload.city = data.city;
    if (data.notes !== undefined) payload.notes = data.notes;
    await supabase.from("suppliers").update(payload).eq("id", id);
    set((s) => ({ suppliers: s.suppliers.map((sup) => (sup.id === id ? { ...sup, ...data } : sup)) }));
  },

  deleteSupplier: async (id) => {
    await supabase.from("suppliers").delete().eq("id", id);
    set((s) => ({ suppliers: s.suppliers.filter((sup) => sup.id !== id) }));
  },

  addTransaction: async (data) => {
    const { data: row, error } = await supabase.from("supplier_transactions").insert({
      supplier_id: data.supplierId, supplier_name: data.supplierName, type: data.type,
      amount: data.amount, pieces: data.pieces, fabric_type: data.fabricType || "",
      fabric_unit: data.fabricUnit || "متر", fabric_quantity: data.fabricQuantity || 0,
      date: data.date, notes: data.notes || "",
    }).select().single();
    if (error) { toast.error("فشل تسجيل العملية"); return; }
    set((s) => ({ transactions: [{ id: row.id, ...data }, ...s.transactions] }));
  },

  deleteTransaction: async (id) => {
    await supabase.from("supplier_transactions").delete().eq("id", id);
    set((s) => ({ transactions: s.transactions.filter((t) => t.id !== id) }));
  },

  getSupplierBalance: (supplierId) => {
    const txs = get().transactions.filter((t) => t.supplierId === supplierId);
    const totalPurchases = txs.filter((t) => t.type === "purchase").reduce((s, t) => s + t.amount, 0);
    const totalPayments = txs.filter((t) => t.type === "payment").reduce((s, t) => s + t.amount, 0);
    const totalReturns = txs.filter((t) => t.type === "return").reduce((s, t) => s + t.amount, 0);
    const totalPieces = txs.filter((t) => t.type === "purchase").reduce((s, t) => s + t.pieces, 0) - txs.filter((t) => t.type === "return").reduce((s, t) => s + t.pieces, 0);
    // Fabric by unit
    const fabricByUnit: Record<string, number> = {};
    txs.forEach((t) => {
      if (t.fabricQuantity > 0) {
        const unit = t.fabricUnit || "متر";
        const multiplier = t.type === "return" ? -1 : t.type === "purchase" ? 1 : 0;
        fabricByUnit[unit] = (fabricByUnit[unit] || 0) + (t.fabricQuantity * multiplier);
      }
    });
    return { totalPurchases, totalPayments, totalReturns, remaining: totalPurchases - totalPayments - totalReturns, totalPieces, fabricByUnit };
  },

  getSupplierTransactions: (supplierId) => get().transactions.filter((t) => t.supplierId === supplierId).sort((a, b) => b.date.localeCompare(a.date)),

  getTotalSupplierDebt: () => {
    const state = get();
    return state.suppliers.reduce((total, sup) => {
      const balance = get().getSupplierBalance(sup.id);
      return total + Math.max(0, balance.remaining);
    }, 0);
  },

  getTotalFabricByUnit: () => {
    const txs = get().transactions;
    const result: Record<string, number> = {};
    txs.forEach((t) => {
      if (t.fabricQuantity > 0) {
        const unit = t.fabricUnit || "متر";
        const multiplier = t.type === "return" ? -1 : t.type === "purchase" ? 1 : 0;
        result[unit] = (result[unit] || 0) + (t.fabricQuantity * multiplier);
      }
    });
    return result;
  },
}));
